import{_ as c,o,c as s,F as d,B as h,j as t,t as a,k as l,d as g,a as r,E as u}from"./chunks/framework.BidWsogY.js";const p=JSON.parse('[{"title":"盘点前端程序员最应该关注的技术发展反向","content":"# 盘点前端程序员最应该关注的技术发展方向\\n\\n作为一名前端开发者，我们身处技术迭代最快的领域之一。从最初的静态页面到如今的复杂单页应用，前端的技术栈早已不是\\"HTML + CSS + JavaScript\\"那么简单。持续跟进各项规范与标准，理解技术发展的方向，对我们的职业成长至关重要。\\n\\n这篇文章将从**语言规范、样式规范、Web平台规范、框架规范、构建工具与生态规范**等多个维度，系统梳理前端开发者最应该关注的规范与标准，并附上权威链接及订阅方式。\\n\\n---\\n\\n## 一、核心语言规范\\n\\n### 1. ECMAScript（JavaScript）规范\\n\\nECMAScript 是 JavaScript 的语言标准，由 **TC39 委员会**（Technical Committee 39）维护。每年发布一个新版本（ES2020、ES2021、ES2022、ES2023、ES2024……），每个提案从 Stage 0 到 Stage 4 逐步成熟。\\n\\n- **官方规范（ECMA-262）**：[https://tc39.es/ecma262/](https://tc39.es/ecma262/)\\n- **TC39 提案仓库（GitHub）**：[https://github.com/tc39/proposals](https://github.com/tc39/proposals)\\n- **已完成提案列表**：[https://github.com/tc39/proposals/blob/main/finished-proposals.md](https://github.com/tc39/proposals/blob/main/finished-proposals.md)\\n- **Stage 0 草案（尚未正式进入流程的新想法）**：[https://github.com/tc39/proposals/blob/main/stage-0-proposals.md](https://github.com/tc39/proposals/blob/main/stage-0-proposals.md)\\n\\n**如何订阅更新？**\\n- 关注 TC39 的 [GitHub Discussions](https://github.com/tc39/ecma262/discussions)\\n- 订阅 [ES Weekly](https://esweekly.com/) 邮件列表\\n- 关注 [@TC39](https://twitter.com/TC39) 官方 Twitter/X 账号\\n- TC39 会议纪要可在 [https://github.com/tc39/notes](https://github.com/tc39/notes) 查阅\\n\\n**近两年值得关注的新特性：**\\n- `Array.groupBy` / `Map.groupBy`\\n- `Promise.withResolvers`\\n- `Decorators`（装饰器，Stage 3）\\n- `Temporal`（全新的日期时间 API，Stage 3）\\n- `RegExp Modifiers`（正则修饰符，Stage 3）\\n- `ShadowRealm`（隔离执行上下文，Stage 3）\\n\\n---\\n\\n### 2. TypeScript 规范\\n\\nTypeScript 本身没有像 ECMA 那样的\\"标准规范\\"，但它的**语言演进和版本发布**由微软的 TypeScript 团队主导。而 **TC39 的提案往往也是 TypeScript 新特性的先导**——TypeScript 团队与 TC39 保持紧密合作。\\n\\n- **TypeScript 官方发布说明**：[https://devblogs.microsoft.com/typescript/](https://devblogs.microsoft.com/typescript/)\\n- **TypeScript 语言规范（已归档）**：[https://github.com/microsoft/TypeScript-Website/tree/main/packages/documentation/copy/en/spec.md](https://github.com/microsoft/TypeScript-Website/tree/main/packages/documentation/copy/en/spec.md)\\n- **TypeScript Roadmap（里程碑规划）**：[https://github.com/microsoft/TypeScript/wiki/Roadmap](https://github.com/microsoft/TypeScript/wiki/Roadmap)\\n- **TypeScript Playground（在线试玩）**：[https://www.typescriptlang.org/play/](https://www.typescriptlang.org/play/)\\n\\n**重要进展方向：**\\n- **`const` 类型参数**（TypeScript 5.0+）\\n- **装饰器（Decorators）**（TS 5.0 正式支持，与 TC39 即将到来的装饰器标准接轨）\\n- **`satisfies` 操作符**\\n- **Isolated Declarations**（`--isolatedDeclarations`，大幅提升类型生成速度）\\n- **更好的 ESM 支持**\\n\\n**如何订阅更新？**\\n- 订阅 [TypeScript Blog 的 RSS](https://devblogs.microsoft.com/typescript/feed/)\\n- 关注 [@typescript](https://twitter.com/typescript) 官方账号\\n- 收藏 [TypeScript 发布说明列表](https://devblogs.microsoft.com/typescript/tag/release/)，每个版本都有详细的 breaking changes 与新特性\\n\\n---\\n\\n### 3. HTML 规范\\n\\nHTML 规范由 **WHATWG（Web Hypertext Application Technology Working Group）** 维护，采用 **Living Standard**（活标准）模式——不再有版本号，持续更新。\\n\\n- **HTML Living Standard（官方规范）**：[https://html.spec.whatwg.org/](https://html.spec.whatwg.org/)\\n- **HTML 规范开发者版本（便于阅读）**：[https://html.spec.whatwg.org/dev/](https://html.spec.whatwg.org/dev/)\\n- **WHATWG GitHub 组织**：[https://github.com/whatwg](https://github.com/whatwg)\\n- **HTML 变更日志**：[https://html.spec.whatwg.org/multipage/acknowledgements.html#change-controller](https://html.spec.whatwg.org/multipage/acknowledgements.html#change-controller)\\n\\n**值得关注的新元素与 API：**\\n- `<dialog>` 元素（原生模态框）\\n- `<popover>` API + `popover` 属性\\n- `<template>` / `<slot>` 与 Web Components 生态\\n- **Declarative Shadow DOM**（声明式 Shadow DOM）\\n- **View Transitions API**（视图过渡动画）\\n- **Navigation API**（SPA 路由原生化）\\n\\n**如何订阅更新？**\\n- 订阅 WHATWG 的 [Twitter/X](https://twitter.com/whatwg)\\n- 加入 [whatwg/HTML 的 GitHub Watch](https://github.com/whatwg/html) 关注 release 与 issue\\n- 查看 [CSS-Tricks 的 HTML 相关文章](https://css-tricks.com/tag/html/)\\n\\n---\\n\\n## 二、样式规范\\n\\n### 4. CSS 规范\\n\\nCSS 由 **CSS Working Group（CSSWG）** 维护。CSS 同样采用模块化方式演进，每个模块有自己的规范版本（如 CSS Grid 规范、CSS Containment 规范等）。所有模块逐步向 **\\"CSS Snapshot\\"** 聚合。\\n\\n- **CSS 官方规范索引**：[https://www.w3.org/Style/CSS/current-work](https://www.w3.org/Style/CSS/current-work)\\n- **CSS Working Group 发布列表**：[https://www.w3.org/TR/CSS/](https://www.w3.org/TR/CSS/)\\n- **CSS Snapshot（年度快照）**：[https://www.w3.org/TR/css-2023/](https://www.w3.org/TR/css-2023/)\\n- **CSSWG 提案与讨论（GitHub）**：[https://github.com/w3c/csswg-drafts](https://github.com/w3c/csswg-drafts)\\n- **Can I Use（浏览器兼容性查询）**：[https://caniuse.com/](https://caniuse.com/)\\n- **CSS DB（CSS 特性进度跟踪）**：[https://cssdb.org/](https://cssdb.org/)\\n\\n**值得关注的新 CSS 特性：**\\n- **CSS Container Queries**（容器查询 —— `@container`）\\n- **CSS :has() 选择器**\\n- **CSS Nesting**（嵌套语法，原生 CSS 支持）\\n- **CSS Scoping**（`@scope` 规则）\\n- **CSS Anchor Positioning**（锚点定位，Stage 2，实现弹出层、工具提示等场景）\\n- **CSS View Transitions**（`@view-transition` + `view-transition-name`）\\n- **CSS `@layer` 规则**（级联层控制优先级）\\n- **CSS `color-mix()`** 与 **相对颜色语法**（`oklch(from var(--color) ...)`）\\n- **CSS Subgrid**（子网格对齐）\\n\\n**如何订阅更新？**\\n- 订阅 [CSSWG 的 Twitter/X](https://twitter.com/csswg)\\n- 监控 [csswg-drafts GitHub 仓库](https://github.com/w3c/csswg-drafts) 的 issue 与 PR\\n- 订阅 [CSS Weekly](https://css-weekly.com/) 邮件\\n- 关注 [@css](https://twitter.com/css) Twitter 列表\\n\\n---\\n\\n### 5. CSS 预处理器与后处理器\\n\\n虽然原生 CSS 已经越来越强大，但 Sass/SCSS、Less、PostCSS 等工具依然在实际项目中有大量使用。\\n\\n- **Sass 文档**：[https://sass-lang.com/documentation/](https://sass-lang.com/documentation/)\\n- **PostCSS 文档**：[https://postcss.org/](https://postcss.org/)\\n- **Lightning CSS（基于 Rust 的快速 CSS 处理）**：[https://lightningcss.dev/](https://lightningcss.dev/)\\n\\n---\\n\\n### 6. CSS 框架与设计方法论\\n\\n现代 CSS 早已不是\\"手写类名 + 全局样式\\"的时代。**Utility-First（工具优先）**、**Headless（无头组件）**、**CSS-in-JS** 等设计方法论深刻改变了前端样式编写方式。\\n\\n#### 6.1 Tailwind CSS（Utility-First 框架）\\n\\nTailwind CSS 是目前最流行的 Utility-First CSS 框架，它提供了一套原子化的工具类，让你直接在 HTML 中组合样式，无需编写自定义 CSS。\\n\\n- **Tailwind CSS 官方文档**：[https://tailwindcss.com/](https://tailwindcss.com/)\\n- **Tailwind CSS v4 发布说明**：[https://tailwindcss.com/blog/tailwindcss-v4](https://tailwindcss.com/blog/tailwindcss-v4)\\n- **Tailwind Playground（在线试玩）**：[https://play.tailwindcss.com/](https://play.tailwindcss.com/)\\n- **Tailwind UI（官方组件库）**：[https://tailwindui.com/](https://tailwindui.com/)\\n\\n**Tailwind v4 重要变化：**\\n- 使用 **CSS-first configuration**（基于原生 CSS `@import` 和 `@theme` 配置，不再需要 `tailwind.config.js`）\\n- 基于 **Lightning CSS** 的构建管道，速度大幅提升\\n- 原生 CSS 嵌套支持\\n- 新的 `@variant` 指令\\n\\n**如何订阅更新？**\\n- 关注 [@tailwindcss](https://twitter.com/tailwindcss) 官方账号\\n- 订阅 [Tailwind CSS 博客](https://tailwindcss.com/blog)\\n\\n#### 6.2 UnoCSS（按需原子化 CSS 引擎）\\n\\nUnoCSS 由 Vite 核心成员 **Anthony Fu** 创建，是一个**按需生成**的原子化 CSS 引擎。它不提供预设的类名集合，而是通过**规则（Rules）** 和 **预设（Presets）** 按需生成样式，性能极高且可定制性极强。\\n\\n- **UnoCSS 官方文档**：[https://unocss.dev/](https://unocss.dev/)\\n- **UnoCSS GitHub 仓库**：[https://github.com/unocss/unocss](https://github.com/unocss/unocss)\\n- **UnoCSS Playground**：[https://unocss.dev/play/](https://unocss.dev/play/)\\n- **UnoCSS 交互式文档**：[https://unocss.dev/interactive/](https://unocss.dev/interactive/)\\n\\n**UnoCSS 核心特性：**\\n- **按需生成**：只生成你实际用到的 CSS，体积极小\\n- **完全可定制**：通过 Rules、Shortcuts、Variants 自定义任意工具类\\n- **预设系统**：官方提供 Tailwind、Windi CSS、Bootstrap、Material 等预设，可一键切换\\n- **纯 CSS 图标**：通过 `@unocss/preset-icons` 使用任意图标库（Iconify），无需额外构建步骤\\n- ** Attributify Mode**：用属性方式写类名（`<div text=\\"center\\" bg=\\"blue-400\\">`）\\n- **与 Vite / Nuxt / Astro / SvelteKit 深度集成**\\n\\n**如何订阅更新？**\\n- 关注 [UnoCSS GitHub Releases](https://github.com/unocss/unocss/releases)\\n- 关注 [@antfu7](https://twitter.com/antfu7)（Anthony Fu 的 Twitter）\\n\\n#### 6.3 Headless UI 组件库\\n\\nHeadless（无头）组件库提供**无样式的可访问组件逻辑**，让你完全控制 UI 外观，同时确保键盘导航、ARIA 属性、焦点管理等开箱即用。这是目前组件库设计的主流趋势。\\n\\n**主流 Headless 组件库：**\\n\\n- **Radix UI（React）**：[https://www.radix-ui.com/](https://www.radix-ui.com/)\\n  - 提供 40+ 无样式原语组件（Dialog、Popover、Dropdown Menu、Tooltip 等）\\n  - 完全符合 WAI-ARIA 规范\\n  - 被 shadcn/ui 等流行组件库采用\\n\\n- **Headless UI（React / Vue）**：[https://headlessui.com/](https://headlessui.com/)\\n  - 由 Tailwind CSS 团队开发\\n  - 提供 Listbox、Combobox、Disclosure、Dialog 等组件\\n  - 与 Tailwind CSS 完美搭配\\n\\n- **Ark UI（React / Vue / Solid）**：[https://ark-ui.com/](https://ark-ui.com/)\\n  - 基于 **Zag.js**（状态机驱动的 UI 逻辑层）\\n  - 框架无关，一套逻辑适配多个框架\\n  - 提供 30+ 无头组件\\n\\n- **React Aria（React）**：[https://react-spectrum.adobe.com/react-aria/](https://react-spectrum.adobe.com/react-aria/)\\n  - Adobe 出品，基于 React 的 Hooks 和组件\\n  - 提供完整的无障碍支持\\n\\n- **Kobalte（Solid.js）**：[https://kobalte.dev/](https://kobalte.dev/)\\n  - Solid.js 生态的无头组件库\\n\\n- **Reach UI（React）**：[https://reach.tech/](https://reach.tech/)\\n  - 专注于无障碍的 React 组件库\\n\\n**Headless 组件库的共同特点：**\\n- 不提供任何 CSS 样式，只提供行为逻辑\\n- 内置完整的键盘导航和 ARIA 支持\\n- 通过 render props / slots 暴露自定义渲染能力\\n- 通常与 Tailwind CSS / UnoCSS 搭配使用\\n\\n#### 6.4 CSS-in-JS 方案\\n\\nCSS-in-JS 在 React 生态中一直有重要地位，近年来出现了新一代方案。\\n\\n- **Panda CSS**：[https://panda-css.com/](https://panda-css.com/)\\n  - 编译时 CSS-in-JS，零运行时开销\\n  - 支持设计令牌（Design Tokens）、Recipe、Pattern\\n  - 与框架无关（React / Vue / Solid / Svelte）\\n\\n- **StyleX**：[https://stylexjs.com/](https://stylexjs.com/)\\n  - Meta（Facebook）开源的 CSS-in-JS 方案\\n  - 在编译时提取 CSS，运行时几乎为零\\n  - 被 Facebook 内部大规模使用\\n\\n- **Vanilla Extract**：[https://vanilla-extract.style/](https://vanilla-extract.style/)\\n  - 编译时 CSS-in-JS，TypeScript 类型安全\\n  - 生成静态 CSS 文件\\n\\n- **styled-components**：[https://styled-components.com/](https://styled-components.com/)\\n  - 经典的运行时 CSS-in-JS 方案\\n  - 虽然运行时开销较大，但社区生态依然活跃\\n\\n- **Emotion**：[https://emotion.sh/](https://emotion.sh/)\\n  - 另一个流行的运行时 CSS-in-JS 方案\\n\\n#### 6.5 Design Tokens（设计令牌）\\n\\n设计令牌是**跨平台设计系统的原子化构建块**，将颜色、间距、字体、阴影等设计决策抽象为可复用的 Token。W3C 正在制定 **Design Tokens 规范**。\\n\\n- **W3C Design Tokens 规范（草案）**：[https://design-tokens.github.io/community-group/format/](https://design-tokens.github.io/community-group/format/)\\n- **Style Dictionary**（Token 转平台代码工具）：[https://amzn.github.io/style-dictionary/](https://amzn.github.io/style-dictionary/)\\n- **Token Studio（Figma 插件）**：[https://tokens.studio/](https://tokens.studio/)\\n\\n**设计令牌的核心价值：**\\n- 统一设计与开发之间的设计语言\\n- 一次定义，多平台（Web / iOS / Android）自动生成\\n- 支持主题切换（亮色/暗色/高对比度）\\n\\n---\\n\\n## 三、Web 平台与浏览器规范\\n\\n### 7. Web API 规范（W3C）\\n\\nW3C 负责维护大量 Web API 标准，从 DOM、Fetch、Service Worker 到 WebGPU 等。\\n\\n- **W3C 推荐标准列表**：[https://www.w3.org/TR/](https://www.w3.org/TR/)\\n- **W3C 工作组**：[https://www.w3.org/groups/wg/](https://www.w3.org/groups/wg/)\\n- **Web Platform 月度报告**：[https://www.w3.org/blog/tag/web-platform-monthly-summary/](https://www.w3.org/blog/tag/web-platform-monthly-summary/)\\n\\n**核心 Web API：**\\n- **Fetch API**（替代 XMLHttpRequest）\\n- **Service Worker** + **Cache API**（PWA 核心）\\n- **IndexedDB**（客户端数据库，v3 规范进行中）\\n- **WebAssembly**（WASM，Stage 4）\\n- **WebGPU**（下一代图形 API，替代 WebGL）\\n- **WebGL**（OpenGL ES 规范在 Web 的实现）\\n- **WebTransport** + **WebCodecs**（低延迟音视频传输）\\n- **File System Access API**（访问本地文件系统）\\n- **WebHID / WebUSB / Web Serial**（连接硬件设备）\\n- **Clipboard API**、**Screen Wake Lock API**、**Fullscreen API** 等\\n\\n**如何订阅更新？**\\n- 访问 [Web Platform 状态仪表盘](https://webstatus.dev/)\\n- 订阅 [W3C Blog RSS](https://www.w3.org/blog/feed/)\\n- 关注 [Chromium 平台状态](https://chromestatus.com/)\\n\\n---\\n\\n### 8. 浏览器引擎规范（Chromium / Firefox / Safari）\\n\\n前端代码最终运行在浏览器中，了解浏览器引擎的实现在做什么至关重要。\\n\\n**Chromium（Blink / V8）：**\\n- **Chrome 平台状态（新 API 进度）**：[https://chromestatus.com/](https://chromestatus.com/)\\n- **Chrome 发布计划**：[https://chromestatus.com/features#milestone](https://chromestatus.com/features#milestone)\\n- **Chrome 开发者博客**：[https://developer.chrome.com/blog/](https://developer.chrome.com/blog/)\\n- **Chromium 博客**：[https://blog.chromium.org/](https://blog.chromium.org/)\\n- **V8 官方博客**：[https://v8.dev/blog](https://v8.dev/blog)\\n\\n**Firefox（Gecko / SpiderMonkey）：**\\n- **Mozilla 标准参与**：[https://mozilla.github.io/standards-positions/](https://mozilla.github.io/standards-positions/)\\n- **Firefox 发布说明**：[https://developer.mozilla.org/en-US/docs/Mozilla/Firefox/Releases](https://developer.mozilla.org/en-US/docs/Mozilla/Firefox/Releases)\\n\\n**Safari（WebKit / JavaScriptCore）：**\\n- **WebKit 博客**：[https://webkit.org/blog/](https://webkit.org/blog/)\\n- **Safari 版本发布说明**：[https://developer.apple.com/documentation/safari-release-notes](https://developer.apple.com/documentation/safari-release-notes)\\n- **WebKit 标准参与**：[https://webkit.org/standards-positions/](https://webkit.org/standards-positions/)\\n\\n**跨浏览器兼容性工具：**\\n- **Can I Use**：[https://caniuse.com/](https://caniuse.com/)\\n- **MDN 浏览器兼容性数据**：[https://github.com/mdn/browser-compat-data](https://github.com/mdn/browser-compat-data)\\n- **Web Platform Tests**：[https://wpt.fyi/](https://wpt.fyi/)（各浏览器通过标准测试的比例）\\n\\n**如何订阅更新？**\\n- 关注 [@ChromiumDev](https://twitter.com/ChromiumDev)\\n- 关注 [@mozhacks](https://twitter.com/mozhacks)\\n- 关注 [@webkit](https://twitter.com/webkit)\\n- 订阅 [Chrome 开发者 YouTube 频道](https://www.youtube.com/user/ChromeDevelopers)\\n- 订阅 [HTTP 203 播客](https://developers.google.com/web/shows/http203/)\\n\\n---\\n\\n### 9. Web 可访问性规范（WCAG / ARIA）\\n\\n无障碍访问（Accessibility，常缩写为 a11y）越来越受到重视，许多国家和地区已经立法要求网站必须满足可访问性标准。\\n\\n- **WCAG 2.2 规范**：[https://www.w3.org/TR/WCAG22/](https://www.w3.org/TR/WCAG22/)\\n- **WCAG 3.0（开发中）**：[https://www.w3.org/TR/wcag-3.0/](https://www.w3.org/TR/wcag-3.0/)\\n- **WAI-ARIA 1.2 规范**：[https://www.w3.org/TR/wai-aria-1.2/](https://www.w3.org/TR/wai-aria-1.2/)\\n- **ARIA 创作实践**：[https://www.w3.org/WAI/ARIA/apg/](https://www.w3.org/WAI/ARIA/apg/)\\n- **WebAIM（Web 无障碍评估工具）**：[https://webaim.org/](https://webaim.org/)\\n- **axe-core（自动化 a11y 检测库）**：[https://github.com/dequelabs/axe-core](https://github.com/dequelabs/axe-core)\\n\\n---\\n\\n## 四、主流框架规范与演进\\n\\n### 10. Vue 新语法与规范\\n\\nVue 团队在 2023 年底发布了 **Vue 3.4**（代号\\"Slam Dunk\\"），随后又推出 **Vue 3.5**，持续优化响应式系统和 DX。Vue 的演进方向是：更细粒度的响应式、更好的 TypeScript 支持、更小的运行时体积。\\n\\n- **Vue 官方文档**：[https://vuejs.org/](https://vuejs.org/)\\n- **Vue 3.5 发布说明**：[https://blog.vuejs.org/posts/vue-3-5](https://blog.vuejs.org/posts/vue-3-5)\\n- **Vue RFC 仓库（提案讨论）**：[https://github.com/vuejs/rfcs](https://github.com/vuejs/rfcs)\\n- **Vapor Mode（无虚拟 DOM 模式，开发中）**：[https://github.com/vuejs/vue-vapor](https://github.com/vuejs/vue-vapor)\\n- **Vue 2 已进入 EOL（End of Life）**：[https://v2.vuejs.org/eol/](https://v2.vuejs.org/eol/)\\n\\n**需要关注的 Vue 新语法与特性：**\\n- **`<script setup>` 语法糖**（已成为 Vue 3 标准写法）\\n- **`defineModel()` 宏**（双向绑定的新方式）\\n- **`shallowRef()` / `shallowReactive()`**（性能优化）\\n- **`<Teleport>` / `<Suspense>`**（内置组件）\\n- **Vapor Mode（汽化模式）**：Vue 正在探索的摆脱虚拟 DOM 的编译策略，借鉴了 Solid.js 的思路\\n- **Vue DevTools v7**（重构后的全新开发者工具）\\n\\n**生态扩展：**\\n- **VueUse**（组合式 API 工具集）：[https://vueuse.org/](https://vueuse.org/)\\n- **Nuxt 3**（Vue 元框架）：[https://nuxt.com/](https://nuxt.com/)\\n- **Pinia**（状态管理）：[https://pinia.vuejs.org/](https://pinia.vuejs.org/)\\n- **Vite**（构建工具）：[https://vitejs.dev/](https://vitejs.dev/)\\n\\n**如何订阅更新？**\\n- 订阅 [Vue 官方博客](https://blog.vuejs.org/)\\n- 关注 [Vue NYC / Evan You 的演讲视频](https://www.youtube.com/c/VueNYC)\\n- 关注 [@vuejs](https://twitter.com/vuejs) 官方账号\\n- 阅读 [Vue RFC](https://github.com/vuejs/rfcs) 仓库了解未来方向\\n\\n---\\n\\n### 11. React 新规范与演进\\n\\nReact 近几年持续发力 **React Server Components（RSC）**，并在 React 19 中正式支持。React 的演进路线正逐步转向以服务端渲染为核心，优化并发体验，简化客户端 API。\\n\\n- **React 官方文档**：[https://react.dev/](https://react.dev/)\\n- **React 19 发布说明**：[https://react.dev/blog/2024/04/25/react-19](https://react.dev/blog/2024/04/25/react-19)\\n- **React RFC 仓库**：[https://github.com/reactjs/rfcs](https://github.com/reactjs/rfcs)\\n- **React Server Components 介绍**：[https://react.dev/blog/2023/03/22/react-labs-what-we-have-been-working-on-march-2023](https://react.dev/blog/2023/03/22/react-labs-what-we-have-been-working-on-march-2023)\\n- **React 语言服务**：[https://react.dev/learn](https://react.dev/learn)\\n\\n**React 19 关键新特性：**\\n- **React Server Components（RSC）**：服务端组件，零客户端 JS 体积\\n- **Actions**：`<form action={...}>` 和 `useActionState()`\\n- **`use()` Hook**：在渲染期间读取资源（Promise / Context）\\n- **`useOptimistic()`**：乐观更新 UI 的 Hook\\n- **`<Context.Provider>` 简化为 `<Context>`**\\n- **`ref` 作为 prop**（不再需要 `forwardRef`）\\n- **更好的 `<meta>` / `<link>` 管理**（文档元数据内建支持）\\n\\n**生态扩展：**\\n- **Next.js**（React 元框架）：[https://nextjs.org/](https://nextjs.org/)\\n- **Zustand**（状态管理）：[https://github.com/pmndrs/zustand](https://github.com/pmndrs/zustand)\\n- **TanStack Query**（数据获取）：[https://tanstack.com/query/](https://tanstack.com/query/)\\n- **React Router**（路由，v7 支持 RSC）：[https://reactrouter.com/](https://reactrouter.com/)\\n\\n**如何订阅更新？**\\n- 订阅 [React 官方博客](https://react.dev/blog)\\n- 关注 [@reactjs](https://twitter.com/reactjs) 官方账号\\n- 关注 React 核心成员：[@dan_abramov](https://twitter.com/dan_abramov)、[@acdlite](https://twitter.com/acdlite)、[@sebmarkbage](https://twitter.com/sebmarkbage)\\n- 订阅 [React Status 周刊](https://react.statuscode.com/)\\n\\n---\\n\\n### 12. Svelte 新语法与规范\\n\\nSvelte 通过编译器将组件编译为高效的纯 JS，2023 年发布的 **Svelte 5** 带来了全新的 **Runes**（符文）响应式系统。\\n\\n- **Svelte 官方文档**：[https://svelte.dev/](https://svelte.dev/)\\n- **Svelte 5 发布说明**：[https://svelte.dev/blog/svelte-5-release](https://svelte.dev/blog/svelte-5-release)\\n- **Svelte 5 Runes 介绍**：[https://svelte.dev/blog/runes](https://svelte.dev/blog/runes)\\n- **Svelte RFC 与讨论**：[https://github.com/sveltejs/rfcs](https://github.com/sveltejs/rfcs)\\n- **Svelte 教程（交互式）**：[https://learn.svelte.dev/](https://learn.svelte.dev/)\\n\\n**Svelte 5 关键语法变化（Runes）：**\\n- **`$state()`**：替代 `let` 声明响应式状态\\n- **`$derived()`**：替代 `$:` 计算属性\\n- **`$effect()`**：替代 `$:` 副作用\\n- **`$props()`**：替代 `export let` 声明组件属性\\n- **`$bindable()`**：双向绑定 props\\n- **`$inspect()`**：调试工具\\n\\n**Svelte 的未来方向：**\\n- **SvelteKit 2**（元框架，服务端渲染）\\n- 更好的 TypeScript 集成\\n- 更小的运行时体积\\n- 与 Web 标准更紧密的对齐\\n\\n**如何订阅更新？**\\n- 订阅 [Svelte 官方博客](https://svelte.dev/blog)\\n- 关注 [@sveltejs](https://twitter.com/sveltejs)\\n- 关注 [@Rich_Harris](https://twitter.com/Rich_Harris)（Svelte 创始人）\\n- 订阅 [Svelte 周刊](https://svelteweekly.com/)\\n\\n---\\n\\n### 13. Solid.js 新语法\\n\\n作为\\"类 React 语法 + 类 Svelte 编译优化\\"的框架，Solid.js 提供了一种无虚拟 DOM 的高性能方案。\\n\\n- **Solid.js 官方文档**：[https://www.solidjs.com/](https://www.solidjs.com/)\\n- **Solid.js 1.8+ 发布说明**：[https://www.solidjs.com/blog](https://www.solidjs.com/blog)\\n- **Solid.js GitHub**：[https://github.com/solidjs/solid](https://github.com/solidjs/solid)\\n- **SolidStart（Solid.js 元框架）**：[https://start.solidjs.com/](https://start.solidjs.com/)\\n\\n**核心语法特性：**\\n- 原生 JSX，但使用 `createSignal` / `createEffect` / `createMemo`\\n- 细粒度响应式，无需虚拟 DOM Diff\\n- 支持 Server Components（SolidStart）\\n\\n---\\n\\n### 14. Angular 规范\\n\\nAngular 作为一个\\"框架而非库\\"，其规范由 Google 的 Angular 团队制定。Angular 17/18 引入了新的 **\\"可延迟视图\\"（Deferrable Views）**、改进的**控制流语法**以及 **Signals** 响应式系统。\\n\\n- **Angular 官方文档**：[https://angular.dev/](https://angular.dev/)\\n- **Angular 博客**：[https://blog.angular.io/](https://blog.angular.io/)\\n- **Angular RFC 仓库**：[https://github.com/angular/angular/discussions/categories/rfc](https://github.com/angular/angular/discussions/categories/rfc)\\n\\n**新语法与方向：**\\n- **`@if` / `@for` / `@switch` 控制流语法**（替代 `*ngIf` / `*ngFor` / `ngSwitch`）\\n- **`@defer` 可延迟加载块**（控制组件加载时机）\\n- **Signals**（`signal()` / `computed()` / `effect()`）\\n- **Standalone Components**（独立组件，不再需要 `NgModule`）\\n- **SSR 增强**（Angular 18+ 对服务端渲染做了大幅重构）\\n\\n---\\n\\n## 五、前端生态规范（Node.js / 模块 / 构建 / 测试）\\n\\n### 15. Node.js 技术栈\\n\\nNode.js 是前端开发者的\\"第二语言\\"。从构建工具、SSR 框架、API 服务到 CLI 工具，Node.js 贯穿了整个前端开发生命周期。\\n\\n#### 15.1 Node.js 运行时规范\\n\\nNode.js 采用 **LTS（Long Term Support）** 发布策略，每年 4 月和 10 月发布主版本，偶数版本进入 LTS（如 20.x、22.x）。\\n\\n- **Node.js 官方文档**：[https://nodejs.org/](https://nodejs.org/)\\n- **Node.js 发布计划（Release Schedule）**：[https://github.com/nodejs/release](https://github.com/nodejs/release)\\n- **Node.js 官方 API 文档**：[https://nodejs.org/api/](https://nodejs.org/api/)\\n- **Node.js 核心模块变更记录（Changelog）**：[https://github.com/nodejs/node/blob/main/CHANGELOG.md](https://github.com/nodejs/node/blob/main/CHANGELOG.md)\\n- **Node.js TypeScript 类型定义（@types/node）**：[https://www.npmjs.com/package/@types/node](https://www.npmjs.com/package/@types/node)\\n\\n**近期重要演进方向：**\\n- **Node.js 与 Web API 标准对齐**：逐步将 Web 标准 API 移植到 Node.js 运行时——如 `fetch()`（原生支持）、`WebStreams`、`WebCrypto`、`EventTarget`、`TextEncoder`/`TextDecoder` 等\\n- **单可执行文件（Single Executable Applications, SEA）**：将 Node.js 脚本编译为单文件可执行程序：[https://nodejs.org/api/single-executable-applications.html](https://nodejs.org/api/single-executable-applications.html)\\n- **ESM 成为一等公民**：Node.js 22 开始默认启用 `--experimental-require-module`，逐步消除 CJS 与 ESM 之间的鸿沟\\n- **TypeScript 原生支持讨论**：Node.js 团队正在讨论是否原生运行 TypeScript（[https://github.com/nodejs/typescript](https://github.com/nodejs/typescript)）\\n- **更好的权限模型（Permission Model）**：类似 Deno 的 `--allow-*` 权限控制\\n\\n**如何订阅更新？**\\n- 订阅 [Node.js 官方博客](https://nodejs.org/en/blog/)\\n- 关注 [@nodejs](https://twitter.com/nodejs) 官方账号\\n- 订阅 [Node Weekly 周刊](https://nodeweekly.com/)\\n\\n#### 15.2 Node.js 后端框架\\n\\nNode.js 生态中有大量后端框架，在不同场景下各有所长：\\n\\n- **Express.js**（最经典的 Web 框架）：[https://expressjs.com/](https://expressjs.com/)\\n- **Fastify**（高性能、基于 Schema 的框架）：[https://fastify.dev/](https://fastify.dev/)\\n- **Koa**（更轻量的中间件模型，由 Express 原班人马打造）：[https://koajs.com/](https://koajs.com/)\\n- **Hono**（超轻量、兼容多种运行时的框架，支持 Cloudflare Workers / Deno / Bun）：[https://hono.dev/](https://hono.dev/)\\n- **NestJS**（受 Angular 启发的全栈框架，TypeScript 优先）：[https://nestjs.com/](https://nestjs.com/)\\n- **AdonisJS**（类似 Laravel 的全栈框架）：[https://adonisjs.com/](https://adonisjs.com/)\\n\\n#### 15.3 Node.js 工具链\\n\\n- **tsx / ts-node**：在 Node.js 中直接运行 TypeScript：[https://tsx.is/](https://tsx.is/) / [https://typestrong.org/ts-node/](https://typestrong.org/ts-node/)\\n- **nodemon**：文件修改后自动重启 Node.js 进程：[https://nodemon.io/](https://nodemon.io/)\\n- **zx**：Google 出品的基于 JavaScript/TypeScript 脚本替代 Bash 的工具：[https://github.com/google/zx](https://github.com/google/zx)\\n- **pkg**：将 Node.js 应用打包为可执行文件：[https://github.com/vercel/pkg](https://github.com/vercel/pkg)\\n- **listhen**：轻量级开发服务器，常用于 Vite / Nitro 生态：[https://github.com/unjs/listhen](https://github.com/unjs/listhen)\\n- **unjs / nitropack**：通用服务端渲染与 API 框架，前端框架无关：[https://nitro.unjs.io/](https://nitro.unjs.io/)\\n\\n#### 15.4 Node.js SSR 与全栈开发\\n\\nNode.js 是前端服务端渲染（SSR）的基石，几乎所有主流元框架都运行在 Node.js 之上：\\n\\n- **Next.js**（React 全栈框架）：[https://nextjs.org/](https://nextjs.org/)\\n- **Nuxt 3**（Vue 全栈框架）：[https://nuxt.com/](https://nuxt.com/)\\n- **SvelteKit**（Svelte 全栈框架）：[https://kit.svelte.dev/](https://kit.svelte.dev/)\\n- **Astro**（内容优先的静态网站框架）：[https://astro.build/](https://astro.build/)\\n- **Remix**（React 全栈框架，被 Shopify 收购）：[https://remix.run/](https://remix.run/)\\n- **SolidStart**（Solid.js 全栈框架）：[https://start.solidjs.com/](https://start.solidjs.com/)\\n- **Analog**（Angular 全栈框架）：[https://analogjs.org/](https://analogjs.org/)\\n\\n**如何订阅更新？**\\n- 关注 [Node.js 发布说明](https://nodejs.org/en/blog/release/)\\n- 订阅 [Node Weekly 周刊](https://nodeweekly.com/)\\n- 关注 [@nodejs](https://twitter.com/nodejs) 获取最新运行时动态\\n\\n---\\n\\n### 16. 模块规范：ES Module vs CommonJS\\n\\nJavaScript 的**模块系统**在演进过程中经历了从 CommonJS 到 ES Module（ESM）的转变。如今 ES Module 已成为标准。\\n\\n- **ES Module 规范（ECMAScript 规范中的一部分）**：[https://tc39.es/ecma262/#sec-modules](https://tc39.es/ecma262/#sec-modules)\\n- **Node.js ESM 文档**：[https://nodejs.org/api/esm.html](https://nodejs.org/api/esm.html)\\n- **Node.js Package 类型文档**：[https://nodejs.org/api/packages.html](https://nodejs.org/api/packages.html)\\n\\n**关键要点：**\\n- `\\"type\\": \\"module\\"` 让 Node.js 项目默认使用 ESM\\n- 库作者需要同时提供 ESM 和 CJS 入口（`\\"exports\\"` 字段）\\n- 浏览器 `<script type=\\"module\\">` 原生支持 ESM\\n- **Import Maps**：浏览器原生映射模块名：[https://github.com/WICG/import-maps](https://github.com/WICG/import-maps)\\n- **JSON Modules**、**CSS Modules**、**Asset Modules**（WICG 提案中）\\n\\n**如何订阅更新？**\\n- 关注 [Node.js 发布说明](https://nodejs.org/en/blog/release/)\\n- 关注 [WICG（Web Incubator Community Group）](https://www.w3.org/community/wicg/)\\n\\n---\\n\\n### 17. 包管理规范：npm / pnpm / bun\\n\\n- **npm 官方文档**：[https://docs.npmjs.com/](https://docs.npmjs.com/)\\n- **pnpm 官方文档**：[https://pnpm.io/](https://pnpm.io/)\\n- **bun 官方文档**：[https://bun.sh/docs](https://bun.sh/docs)\\n- **package.json 规范**：[https://docs.npmjs.com/cli/v10/configuring-npm/package-json](https://docs.npmjs.com/cli/v10/configuring-npm/package-json)\\n- **semver 语义化版本规范**：[https://semver.org/](https://semver.org/)\\n\\n---\\n\\n### 18. 构建工具规范\\n\\n前端构建工具在近几年发生了巨大变革，从 Webpack 到 Vite，再到基于 Rust 的 Turbopack、Rspack。\\n\\n- **Vite 官方文档**：[https://vitejs.dev/](https://vitejs.dev/)\\n- **esbuild 文档**：[https://esbuild.github.io/](https://esbuild.github.io/)\\n- **Rspack（基于 Rust 的高性能 Webpack 替代）**：[https://www.rspack.dev/](https://www.rspack.dev/)\\n- **Turbopack（Next.js 使用的增量计算打包器）**：[https://turbo.build/pack](https://turbo.build/pack)\\n- **Webpack 文档**：[https://webpack.js.org/](https://webpack.js.org/)\\n- **Rollup 文档**：[https://rollupjs.org/](https://rollupjs.org/)\\n\\n**发展方向：**\\n- 从 JS 到 Rust / Go / Zig 的构建工具语言转变\\n- 从 bundle 到 ESM 原生 + bundle 的前后混合策略\\n- **Module Federation**（Webpack 5 远程模块共享）：[https://module-federation.io/](https://module-federation.io/)\\n- **Bundler 无关的 RSC（React Server Components）** 支持\\n\\n---\\n\\n### 19. 测试规范\\n\\n- **Vitest**（与 Vite 集成的测试框架）：[https://vitest.dev/](https://vitest.dev/)\\n- **Playwright**（端到端测试，跨浏览器）：[https://playwright.dev/](https://playwright.dev/)\\n- **Testing Library**（以用户为中心的组件测试）：[https://testing-library.com/](https://testing-library.com/)\\n- **Storybook**（组件开发与测试平台）：[https://storybook.js.org/](https://storybook.js.org/)\\n\\n---\\n\\n### 20. 格式化与代码规范\\n\\n**ESLint** 和 **Prettier** 已经是前端项目标配的代码规范工具，并且社区正在向 **\\"扁平的 ESLint 配置\\"** 迁移（ESLint v9 默认使用 flat config）。\\n\\n- **ESLint 官方文档**：[https://eslint.org/](https://eslint.org/)\\n- **ESLint Flat Config 迁移指南**：[https://eslint.org/docs/latest/use/configure/configuration-files-new](https://eslint.org/docs/latest/use/configure/configuration-files-new)\\n- **Prettier 官方文档**：[https://prettier.io/](https://prettier.io/)\\n- **stylelint（CSS 代码规范检查）**：[https://stylelint.io/](https://stylelint.io/)\\n\\n**规范类型相关建议：**\\n- 团队应统一 ESLint 配置，推荐使用 [@antfu/eslint-config](https://github.com/antfu/eslint-config) 或 [@typescript-eslint](https://typescript-eslint.io/) 配置集\\n- 使用 `.editorconfig` 统一编辑器行为：[https://editorconfig.org/](https://editorconfig.org/)\\n- 使用 **husky** + **lint-staged** 在 Git 提交时自动检查代码：[https://github.com/typicode/husky](https://github.com/typicode/husky)\\n\\n---\\n\\n## 六、如何高效订阅技术规范更新\\n\\n前端技术信息极其碎片化，你需要一套**高效的信息获取体系**。以下是我的建议：\\n\\n### 6.1 RSS 聚合（推荐）\\n\\n很多人的第一反应是订阅公众号或刷 Twitter，但 RSS 依然是**最系统、最不打扰注意力**的方式。推荐使用：\\n\\n- **Feedly**：[https://feedly.com/](https://feedly.com/)\\n- **NetNewsWire**（macOS / iOS 原生 RSS 阅读器）：[https://netnewswire.com/](https://netnewswire.com/)\\n- **Miniflux**（自托管轻量 RSS）：[https://miniflux.app/](https://miniflux.app/)\\n\\n将以下链接添加到 RSS 阅读器：\\n- Mozilla Hacks：[https://hacks.mozilla.org/feed/](https://hacks.mozilla.org/feed/)\\n- WebKit Blog：[https://webkit.org/feed/](https://webkit.org/feed/)\\n- Chrome Developers：[https://developer.chrome.com/feed.xml](https://developer.chrome.com/feed.xml)\\n- Vue Blog：[https://blog.vuejs.org/feed.xml](https://blog.vuejs.org/feed.xml)\\n- React Blog：[https://react.dev/blog](https://react.dev/blog)（无原生 RSS，可用 [RSSHub](https://rsshub.app/) 生成）\\n- Svelte Blog：[https://svelte.dev/blog](https://svelte.dev/blog)（可在 RSSHub 生成）\\n- TypeScript Blog：[https://devblogs.microsoft.com/typescript/feed/](https://devblogs.microsoft.com/typescript/feed/)\\n\\n### 6.2 GitHub Watch\\n\\n对于 TC39、CSSWG、WICG、各大框架的 RFC 仓库，直接添加 **GitHub Watch**（Releases only + Issues 通知），就不会错过任何规范更新。\\n\\n### 6.3 邮件周刊\\n\\n- **[ES Weekly](https://esweekly.com/)**：ECMAScript 最新动态\\n- **[CSS Weekly](https://css-weekly.com/)**：CSS 最新文章与规范更新\\n- **[React Status](https://react.statuscode.com/)**：React 生态周刊\\n- **[JavaScript Weekly](https://javascriptweekly.com/)**：JS 综合周刊\\n- **[Node Weekly](https://nodeweekly.com/)**：Node.js 生态周刊\\n- **[Web Tools Weekly](https://webtoolsweekly.com/)**：前端工具更新\\n\\n### 6.4 社交媒体与社区\\n\\n- Twitter/X：关注上述框架和团队的官方账号\\n- **前端之巅**（知乎专栏）：国内前端技术动态汇总\\n- **Hacker News**：[https://news.ycombinator.com/](https://news.ycombinator.com/)：用 `javascript` 或 `frontend` 关键词过滤\\n- **Reddit r/javascript**：[https://www.reddit.com/r/javascript/](https://www.reddit.com/r/javascript/)\\n- **掘金**：[https://juejin.cn/](https://juejin.cn/)：国内高质量前端文章\\n\\n### 6.5 年度报告\\n\\n- **State of JS 调研报告**：[https://stateofjs.com/](https://stateofjs.com/)\\n- **State of CSS 调研报告**：[https://stateofcss.com/](https://stateofcss.com/)\\n- **年度 Web 算法报告**（HTTP Archive）：[https://almanac.httparchive.org/](https://almanac.httparchive.org/)\\n- **MDN Web 开发年度调查**：[https://survey.mozilla.org/](https://survey.mozilla.org/)\\n\\n---\\n\\n## 七、总结\\n\\n前端技术发展的本质，是 **Web 平台能力的不断增强**。在关注框架和工具之前，更要理解底层的标准规范——因为框架和工具只是规范的实现，而规范的演进决定了整个行业的方向。\\n\\n我对前端开发者的个人建议是：\\n\\n1. **深入理解规范**：将 HTML、CSS、ES 规范视为基础必修课\\n2. **保持对提案的关注**：至少每季度浏览一次 TC39 提案和 CSSWG 草案\\n3. **拥抱 Web 原生 API**：框架可以帮你提高效率，但 Web 原生 API 才是你的护城河\\n4. **建立自己的信息渠道**：用 RSS + GitHub Watch + 邮件周刊构建信息漏斗\\n5. **动手实践**：新规范出来时，打开 Playground 或 CodeSandbox 试一试是最快的学习方式\\n\\n前端这条路很长，风景时刻在变，但保持对规范和标准的敏感度，会让你走得更远。\\n\\n---\\n\\n> 文章首发于 [codemyhappy.github.io](https://codemyhappy.github.io/)，转载请注明出处。","lastUpdated":1783559718083},{"title":"了解大模型的第二语言，纷繁复杂的markdown规范","content":"# 了解大模型的第二语言，纷繁复杂的 Markdown 规范\\n\\n## 前言\\n\\n如果你经常和 ChatGPT、Claude 等大语言模型打交道，你会发现它们最擅长输出的格式就是 Markdown。无论是写代码、列清单、做表格，还是写一篇完整的文章，Markdown 几乎成了大模型与人类之间的\\"第二语言\\"。\\n\\n但 Markdown 有一个\\"历史遗留问题\\"——它从来没有一个真正统一的官方标准。从 John Gruber 在 2004 年发布最初的 Markdown 语法以来，各路实现者根据自己的需求不断扩展，衍生出了十几种不同的规范。这就导致了一个尴尬的局面：同一份 Markdown 源码，在不同的渲染器下可能呈现出完全不同的效果。\\n\\n本文将带你梳理主流的 Markdown 规范，分析不同前端（渲染器）的处理差异，并给出让 Markdown 源码跨规范保持一致的实用建议。\\n\\n## 一、主流 Markdown 规范概览\\n\\n### 1. CommonMark\\n\\n- **官方规范**：[https://spec.commonmark.org](https://spec.commonmark.org)\\n- **GitHub 仓库**：[https://github.com/commonmark/commonmark-spec](https://github.com/commonmark/commonmark-spec)\\n\\nCommonMark 是 Markdown 社区为了终结碎片化而发起的一个标准化项目。它定义了一套严格、无歧义的规范，并提供了官方测试套件。\\n\\n- **特点**：语法严格、行为可预测、有完整的规范文档\\n- **典型实现**：`cmark`（C 语言参考实现）、`markdown-it`（默认模式）、`remark`（基于 AST 的解析器）\\n- **适用场景**：追求标准化的通用场景\\n\\nCommonMark 解决了很多原始 Markdown 的歧义问题，比如：\\n\\n```markdown\\n**加粗*部分加粗*部分加粗**\\n```\\n\\n在原始 Markdown 中，这段代码的行为是不确定的。CommonMark 明确规定了嵌套强调的解析规则。\\n\\n#### CommonMark 的核心设计原则\\n\\nCommonMark 之所以重要，是因为它解决了原始 Markdown 中大量\\"未定义行为\\"的问题。以下是它的一些关键设计：\\n\\n**（1）明确的优先级规则**\\n\\nCommonMark 定义了严格的块级元素优先级。例如，一个 `>` 开头的行到底是引用还是普通文本？CommonMark 规定：如果一行以 `>` 开头且后面跟一个空格，它就是块引用；如果 `>` 后面紧跟非空格字符，则 `>` 被视为普通文本。\\n\\n```markdown\\n> 这是引用\\n\\n>这不是引用，>是普通文本\\n```\\n\\n**（2）容器块与叶块的分层结构**\\n\\nCommonMark 将块级元素分为两类：\\n\\n- **容器块**（Container blocks）：可以包含其他块，如块引用（`>`）、列表项（`-`/`*`/`1.`）\\n- **叶块**（Leaf blocks）：不能包含其他块，如段落、标题、代码块、水平线\\n\\n这种分层结构让解析器可以递归处理嵌套结构，行为非常清晰。\\n\\n**（3）列表的严格规则**\\n\\n原始 Markdown 中列表的缩进和嵌套规则非常模糊。CommonMark 明确规定了：\\n\\n- 列表项的缩进从标记符（`-`、`*`、`1.`）后的第一个非空格字符开始计算\\n- 有序列表的起始数字有意义（`3. 条目` 会从 3 开始编号）\\n- 列表项可以包含多个段落，但后续段落必须缩进\\n\\n```markdown\\n- 第一项\\n\\n  这是第一项的第二个段落（缩进 2 空格或更多）\\n\\n- 第二项\\n```\\n\\n**（4）信息字符串（Info String）**\\n\\nCommonMark 的围栏代码块支持信息字符串（通常用于标注语言），但规范明确规定信息字符串仅作为元数据，渲染器可以选择忽略或使用它。\\n\\n\\n**（5）实体和字符引用**\\n\\nCommonMark 支持 HTML 实体（`&`）和数字字符引用（`&#60;`），并规定了它们在行内代码和代码块中的转义行为。\\n\\n#### CommonMark 的局限性\\n\\nCommonMark 虽然解决了标准化问题，但它有意保持\\"最小化\\"——只包含最核心的语法，不包含表格、任务列表、删除线、脚注等实用扩展。这意味着：\\n\\n- CommonMark 本身不适合直接用于内容创作（缺少太多实用功能）\\n- 它更适合作为其他规范的基础层（如 GFM 就是在 CommonMark 之上扩展的）\\n- 如果你只使用 CommonMark 语法，你的内容在任何平台上都能正确渲染，但功能有限\\n\\n### 2. GitHub Flavored Markdown (GFM)\\n\\n- **官方规范**：[https://github.github.com/gfm](https://github.github.com/gfm)\\n- **GitHub 仓库**：[https://github.com/github/cmark-gfm](https://github.com/github/cmark-gfm)\\n\\nGFM 是 GitHub 在 CommonMark 基础上扩展的一套规范，是目前使用最广泛的 Markdown 方言之一。\\n\\n- **特点**：基于 CommonMark，增加了大量实用扩展\\n- **典型实现**：`cmark-gfm`、`remark-gfm`\\n- **适用场景**：GitHub、GitLab、GitBook 等代码协作平台\\n\\nGFM 在 CommonMark 基础上增加了：\\n\\n- **表格**（Table）：使用 `|` 和 `-` 绘制\\n- **任务列表**（Task List）：`- [x]` 和 `- [ ]`\\n- **删除线**（Strikethrough）：`~~文本~~`\\n- **自动链接**（Autolink）：URL 自动转为可点击链接\\n- **围栏代码块**（Fenced Code Block）：支持语言标注\\n- **Emoji**：`:smile:` 简码支持\\n\\n### 3. Markdown Extra\\n\\n- **官方文档**：[https://michelf.ca/projects/php-markdown/extra](https://michelf.ca/projects/php-markdown/extra/)\\n\\nMarkdown Extra 是 PHP 生态中流行的扩展规范，由 Michel Fortin 在 2005 年提出。\\n\\n- **特点**：在原始 Markdown 基础上增加了轻量级扩展\\n- **典型实现**：PHP Markdown Extra、Python-Markdown（extra 扩展）\\n- **适用场景**：WordPress、Drupal 等 CMS 系统\\n\\n主要扩展包括：\\n\\n- **表格**（与 GFM 类似但语法略有差异）\\n- **脚注**（Footnote）：`[^1]` 语法\\n- **定义列表**（Definition List）\\n- **缩写**（Abbreviation）\\n- **围栏代码块**（早期实现之一）\\n\\n### 4. Pandoc Markdown\\n\\n- **官方文档**：[https://pandoc.org/MANUAL.html#pandocs-markdown](https://pandoc.org/MANUAL.html#pandocs-markdown)\\n\\nPandoc 是一个文档格式转换工具，它定义了自己的一套 Markdown 方言，几乎是最全功能的 Markdown 规范。\\n\\n- **特点**：功能极其丰富，支持多种输出格式\\n- **典型实现**：Pandoc\\n- **适用场景**：文档格式转换、学术出版\\n\\nPandoc Markdown 支持：\\n\\n- **YAML 元数据块**\\n- **数学公式**（多种语法）\\n- **脚注**、**引文**、**参考文献**\\n- **表格**（多种风格：简单表、网格表、管道表）\\n- **围栏代码块**（带属性）\\n- **原始 HTML/LaTeX 内联**\\n- **目录**、**图表标题**、**交叉引用**\\n\\n### 5. Obsidian Flavored Markdown\\n\\n- **官方文档**：[https://help.obsidian.md/Editing+and+formatting/Obsidian+Flavored+Markdown](https://help.obsidian.md/Editing+and+formatting/Obsidian+Flavored+Markdown)\\n\\nObsidian 作为目前最流行的知识管理工具，也发展出了自己的 Markdown 方言。\\n\\n- **特点**：强调双向链接和知识图谱\\n- **典型实现**：Obsidian 内置渲染器\\n- **适用场景**：个人知识管理、笔记系统\\n\\n特色语法：\\n\\n- **Wiki 链接**：`[[笔记名]]` 双向链接\\n- **块引用**：`^block-id`\\n- **Callout**：`> [!note]` 提示块\\n- **Mermaid 图表**：内建支持\\n- **LaTeX 数学**：`$...$` 和 `$$...$$`\\n- **标签**：`#tag` 语法\\n\\n### 6. VuePress / VitePress Markdown\\n\\n- **VitePress 文档**：[https://vitepress.dev/guide/markdown](https://vitepress.dev/guide/markdown)\\n- **VuePress 文档**：[https://vuepress.vuejs.org/guide/markdown](https://vuepress.vuejs.org/guide/markdown)\\n\\nVuePress 和 VitePress 是 Vue 生态的静态站点生成器，它们基于 markdown-it 做了大量扩展。\\n\\n- **特点**：面向文档站点，支持 Vue 组件嵌入\\n- **典型实现**：VuePress、VitePress\\n- **适用场景**：技术文档、个人博客\\n\\n特色功能：\\n\\n- **Frontmatter**：YAML 头部元数据\\n- **自定义容器**：`::: tip`、`::: warning` 等\\n- **代码组**（Code Group）：Tab 切换代码块\\n- **Vue 组件内嵌**：在 Markdown 中直接使用 Vue 组件\\n- **图片优化**：自动缩放、懒加载\\n- **目录**：`[[toc]]` 语法\\n\\n## 二、Markdown 编辑器与渲染引擎\\n\\n除了规范本身，实际开发中我们接触更多的是各种 Markdown 编辑器和渲染引擎。它们有的基于规范实现，有的自创了一套解析体系。了解它们的工作原理，有助于我们理解 Markdown 在不同场景下的行为差异。\\n\\n### 1. markdown-it\\n\\n- **GitHub 仓库**：[https://github.com/markdown-it/markdown-it](https://github.com/markdown-it/markdown-it)\\n\\nmarkdown-it 是目前最流行的 JavaScript Markdown 解析器之一，也是 VuePress、VitePress 等工具的底层引擎。\\n\\n- **特点**：速度快、插件生态丰富、严格遵循 CommonMark\\n- **默认模式**：严格 CommonMark 模式\\n- **扩展方式**：通过插件机制添加语法支持\\n\\nmarkdown-it 的架构非常清晰：\\n\\n```\\nMarkdown 源码 → Parser（解析为 Token 流） → Renderer（渲染为 HTML）\\n```\\n\\n它支持通过插件在解析阶段注入自定义规则，比如：\\n\\n- `markdown-it-table`：表格支持\\n- `markdown-it-emoji`：Emoji 支持\\n- `markdown-it-tex`：数学公式支持\\n- `markdown-it-footnote`：脚注支持\\n\\n**使用示例**：\\n\\n```javascript\\nconst md = require(\'markdown-it\')();\\nconst result = md.render(\'# Hello World\');\\n// <h1>Hello World</h1>\\n```\\n\\n**开启 GFM 模式**：\\n\\n```javascript\\nconst md = require(\'markdown-it\')({\\n  html: true,\\n  linkify: true,\\n  typographer: true\\n});\\n```\\n\\n### 2. MDEditor v3\\n\\n- **GitHub 仓库**：[https://github.com/imzbf/md-editor-v3](https://github.com/imzbf/md-editor-v3)\\n\\nMDEditor v3 是一个基于 Vue 3 的 Markdown 编辑器组件，是目前 Vue 生态中最流行的 Markdown 编辑器之一。\\n\\n- **特点**：Vue 3 原生、TypeScript 支持、主题可定制\\n- **底层引擎**：默认使用 markdown-it，可切换为其他解析器\\n- **适用场景**：Vue 3 项目中的 Markdown 编辑功能\\n\\nMDEditor v3 支持：\\n\\n- **双栏编辑**：左侧编辑、右侧实时预览\\n- **工具栏**：丰富的快捷插入按钮（表格、代码块、图片、链接等）\\n- **主题切换**：内置亮色/暗色主题\\n- **自定义扩展**：支持自定义工具栏按钮和渲染规则\\n- **代码高亮**：内置代码语法高亮\\n- **图片上传**：支持拖拽/粘贴上传，可自定义上传处理函数\\n\\n**使用示例**：\\n\\n```vue\\n<template>\\n  <MdEditor v-model=\\"text\\" />\\n</template>\\n\\n<script setup>\\nimport { ref } from \'vue\'\\nimport { MdEditor } from \'md-editor-v3\'\\nimport \'md-editor-v3/lib/style.css\'\\n\\nconst text = ref(\'# Hello World\')\\n<\/script>\\n```\\n\\n它的核心设计是\\"编辑与预览分离\\"——编辑区保持纯文本，预览区通过 markdown-it 渲染为 HTML。这种模式的好处是源码清晰可控，但缺点是无法做到真正的\\"所见即所得\\"（比如表格编辑时无法直观看到对齐效果）。\\n\\n### 3. Notion\\n\\nNotion 是目前最流行的全能型笔记和协作工具，但它**不是**一个 Markdown 编辑器——它有自己的块级编辑器（Block-based Editor），只是**兼容 Markdown 的输入和输出**。\\n\\n- **特点**：块级编辑、数据库驱动、Markdown 导入/导出\\n- **底层引擎**：自研的块级渲染引擎\\n- **Markdown 支持方式**：输入时识别 Markdown 语法并转换为块，导出时渲染为 Markdown\\n\\n**Notion 的 Markdown 处理逻辑**：\\n\\n```\\n输入 Markdown 语法 → 识别为块操作 → 存储为 Notion 内部数据结构\\n导出 Notion 页面 → 将块结构渲染为 Markdown 文本\\n```\\n\\n这意味着：\\n\\n- 在 Notion 中输入 `# 标题` 会立即转换为标题块，不再是纯文本\\n- 从 Notion 导出的 Markdown 可能包含 Notion 特有的块结构标记\\n- 导入 Markdown 到 Notion 时，部分复杂语法可能丢失\\n\\n**支持的 Markdown 语法**：\\n\\n| 语法 | 支持情况 |\\n|------|---------|\\n| `#` 标题 | ✅ 转换为标题块 |\\n| `**` 加粗 | ✅ |\\n| `*` 斜体 | ✅ |\\n| `` ` `` 行内代码 | ✅ |\\n| ``` 代码块 | ✅ |\\n| `-` 无序列表 | ✅ |\\n| `1.` 有序列表 | ✅ |\\n| `[]` 任务列表 | ✅ |\\n| `|` 表格 | ⚠️ 导入支持有限 |\\n| `~~` 删除线 | ✅ |\\n| `>` 引用 | ✅ 转换为引用块 |\\n\\n### 4. TipTap\\n\\n- **官方文档**：[https://tiptap.dev](https://tiptap.dev)\\n- **GitHub 仓库**：[https://github.com/ueberdosis/tiptap](https://github.com/ueberdosis/tiptap)\\n\\nTipTap 是一个基于 ProseMirror 的富文本编辑器框架，它代表了 Markdown 编辑的另一种思路——**不直接编辑 Markdown 源码，而是编辑渲染后的富文本，再序列化为 Markdown**。\\n\\n#### TipTap 的架构\\n\\n```\\n用户操作（输入/粘贴/拖拽）\\n    ↓\\nProseMirror 状态管理（维护文档的 JSON 数据结构）\\n    ↓\\n视图层渲染（DOM 更新）\\n    ↓\\n序列化（将 JSON 结构输出为 Markdown / HTML / 其他格式）\\n```\\n\\n这种架构的核心优势是：**用户看到的就是最终结果**，不存在\\"源码 vs 预览\\"的认知鸿沟。\\n\\n#### TipTap 如何支持 Markdown\\n\\nTipTap 对 Markdown 的支持分为三个层面：\\n\\n**（1）输入时：Markdown 快捷输入（Input Rules）**\\n\\nTipTap 通过 ProseMirror 的 Input Rules 机制，在用户输入时实时识别 Markdown 语法并转换为富文本节点：\\n\\n```javascript\\n// 例如：输入 \\"# \\" 自动转换为标题\\nimport { Heading } from \'@tiptap/extension-heading\'\\n\\n// 输入 \\"> \\" 自动转换为块引用\\nimport { Blockquote } from \'@tiptap/extension-blockquote\'\\n\\n// 输入 \\"**text**\\" 自动转换为加粗\\nimport { Bold } from \'@tiptap/extension-bold\'\\n\\n// 输入 \\"```\\" 自动转换为代码块\\nimport { CodeBlockLowlight } from \'@tiptap/extension-code-block-lowlight\'\\n```\\n\\n这意味着用户在 TipTap 中可以直接用 Markdown 语法快速输入，但最终存储的是结构化的 JSON 数据，而不是 Markdown 文本。\\n\\n**（2）粘贴时：Paste Rules**\\n\\n当用户从外部复制 Markdown 文本粘贴到 TipTap 编辑器时，TipTap 会解析 Markdown 并转换为内部节点结构：\\n\\n```javascript\\n// 开启 Markdown 粘贴支持\\nimport { Markdown } from \'tiptap-markdown\'\\n\\nconst editor = new Editor({\\n  extensions: [\\n    StarterKit,\\n    Markdown.configure({\\n      html: true,        // 允许 HTML\\n      tightLists: true,  // 紧凑列表\\n    }),\\n  ],\\n})\\n```\\n\\n**（3）序列化/反序列化：Markdown 导入导出**\\n\\nTipTap 可以将内部文档结构序列化为 Markdown 文本，也可以将 Markdown 文本反序列化为内部结构：\\n\\n```javascript\\n// 导出为 Markdown\\nconst markdown = editor.storage.markdown.getMarkdown()\\n\\n// 从 Markdown 导入\\neditor.commands.setContent(markdown)\\n```\\n\\n#### TipTap 的 Markdown 扩展生态\\n\\nTipTap 通过扩展机制支持丰富的 Markdown 语法：\\n\\n| 扩展 | 功能 | Markdown 语法 |\\n|------|------|--------------|\\n| `@tiptap/extension-bold` | 加粗 | `**text**` |\\n| `@tiptap/extension-italic` | 斜体 | `*text*` |\\n| `@tiptap/extension-strike` | 删除线 | `~~text~~` |\\n| `@tiptap/extension-code` | 行内代码 | `` `code` `` |\\n| `@tiptap/extension-code-block` | 代码块 | ` ``` ` |\\n| `@tiptap/extension-heading` | 标题 | `#` ~ `######` |\\n| `@tiptap/extension-blockquote` | 引用 | `>` |\\n| `@tiptap/extension-bullet-list` | 无序列表 | `-` / `*` |\\n| `@tiptap/extension-ordered-list` | 有序列表 | `1.` |\\n| `@tiptap/extension-task-list` | 任务列表 | `- [ ]` / `- [x]` |\\n| `@tiptap/extension-table` | 表格 | 通过 UI 插入 |\\n| `@tiptap/extension-image` | 图片 | `![](url)` |\\n| `@tiptap/extension-link` | 链接 | `[text](url)` |\\n| `@tiptap/extension-mention` | @提及 | `@user` |\\n| `@tiptap/extension-emoji` | Emoji | `:smile:` |\\n\\n#### TipTap vs 传统 Markdown 编辑器的区别\\n\\n| 特性 | TipTap（富文本模式） | 传统 Markdown 编辑器 |\\n|------|-------------------|-------------------|\\n| 编辑方式 | 直接编辑渲染结果 | 编辑源码 + 预览 |\\n| 数据存储 | JSON 节点树 | Markdown 文本 |\\n| Markdown 角色 | 输入/输出格式 | 存储格式 |\\n| 表格编辑 | 可视化拖拽调整 | 手动对齐管道符 |\\n| 图片处理 | 拖拽上传 | 手动写 URL |\\n| 复杂排版 | 原生支持 | 需写 HTML 兜底 |\\n\\n#### TipTap 的适用场景\\n\\nTipTap 特别适合以下场景：\\n\\n- **需要富文本编辑体验的应用**：如博客后台、CMS 编辑器、知识库系统\\n- **非技术用户**：不想学习 Markdown 语法的用户\\n- **需要结构化数据的场景**：如协同编辑、版本对比、内容复用\\n- **需要自定义节点**：如嵌入视频、数据库视图、自定义组件\\n\\n但如果你是一个 Markdown 重度用户，习惯直接编辑源码、用 Git 做版本管理，TipTap 的\\"黑盒\\"存储方式可能会让你感到不便——因为最终存储的是 JSON 而不是纯文本 Markdown，无法直接用 `diff` 查看变更。\\n\\n### 5. 其他值得关注的编辑器\\n\\n| 编辑器 | 特点 | 底层引擎 | 适用场景 |\\n|--------|------|---------|---------|\\n| **StackEdit** | 浏览器端、支持同步到多个平台 | marked | 在线写作 |\\n| **Typora** | 所见即所得、极简 UI | 自研 | 本地写作 |\\n| **HackMD / CodiMD** | 实时协同、HackMD 社区版 | markdown-it | 团队协作 |\\n| **Editor.md** | 老牌 Web 编辑器、功能全面 | marked | Web 应用集成 |\\n| **ByteMD** | 字节跳动开源、轻量高性能 | 自研 | React 应用 |\\n| **Milkdown** | 插件化、基于 ProseMirror | ProseMirror | 可定制编辑器 |\\n\\n## 三、不同规范的核心差异对比\\n\\n| 特性 | CommonMark | GFM | Markdown Extra | Pandoc | Obsidian | VitePress |\\n|------|-----------|-----|---------------|--------|----------|-----------|\\n| 表格 | ❌ | ✅ 管道表 | ✅ 管道表 | ✅ 多种 | ✅ | ✅ |\\n| 任务列表 | ❌ | ✅ | ❌ | ✅ | ✅ | ❌ |\\n| 删除线 | ❌ | ✅ `~~` | ❌ | ✅ | ✅ | ✅ |\\n| 脚注 | ❌ | ❌ | ✅ `[^1]` | ✅ | ✅ | ❌ |\\n| 数学公式 | ❌ | ❌ | ❌ | ✅ | ✅ `$$` | ✅ `$$` |\\n| 围栏代码块 | ✅ | ✅ | ✅ | ✅ | ✅ | ✅ |\\n| YAML Frontmatter | ❌ | ❌ | ❌ | ✅ | ✅ | ✅ |\\n| Wiki 链接 | ❌ | ❌ | ❌ | ❌ | ✅ `[[]]` | ❌ |\\n| Callout | ❌ | ❌ | ❌ | ❌ | ✅ | ✅ `:::` |\\n| Mermaid | ❌ | ✅ (渲染) | ❌ | ❌ | ✅ | ✅ |\\n| Emoji 简码 | ❌ | ✅ `:smile:` | ❌ | ❌ | ❌ | ❌ |\\n| 自动链接 | ❌ | ✅ | ❌ | ✅ | ✅ | ✅ |\\n| 定义列表 | ❌ | ❌ | ✅ | ✅ | ❌ | ❌ |\\n| 原始 HTML | ✅ | ✅ | ✅ | ✅ | 受限 | 受限 |\\n\\n## 四、不同前端（渲染器）的处理差异\\n\\n要真正理解不同 Markdown 渲染器之间的差异，最好的方式是自己动手对比。以下是一些在线 Markdown 预览工具，你可以复制同一段 Markdown 源码到不同工具中，直观地观察渲染结果的差异。\\n\\n### 在线预览工具\\n\\n| 工具 | 底层引擎 | 链接 |\\n|------|---------|------|\\n| **CommonMark Dingus** | cmark（CommonMark 官方参考实现） | [https://spec.commonmark.org/dingus](https://spec.commonmark.org/dingus/) |\\n| **GitHub GFM 预览** | cmark-gfm | 在任意 GitHub Issue 或 PR 的评论框中输入 |\\n| **markdown-it 演示** | markdown-it | [https://markdown-it.github.io](https://markdown-it.github.io/) |\\n| **MDEditor v3 在线演示** | markdown-it | [https://imzbf.github.io/md-editor-v3/zh-CN](https://imzbf.github.io/md-editor-v3/zh-CN/) |\\n| **Yaniv Editor 演示** | 自研 | [https://yanivwang.github.io/yaniv-editor/examples/#/full-editor](https://yanivwang.github.io/yaniv-editor/examples/#/full-editor) |\\n| **StackEdit** | marked / markdown-it（可切换） | [https://stackedit.io](https://stackedit.io/) |\\n| **HackMD** | markdown-it | [https://hackmd.io](https://hackmd.io/) |\\n\\n### 建议对比的测试用例\\n\\n你可以将以下 Markdown 片段依次粘贴到上述工具中，观察差异：\\n\\n**测试 1：表格与对齐**\\n\\n```markdown\\n| 左对齐 | 居中 | 右对齐 |\\n| :----- | :--: | ----: |\\n| A      |  B   |     C |\\n```\\n\\n👉 在 CommonMark Dingus 中不会渲染为表格（CommonMark 不支持），在 GFM 和 markdown-it 演示中则正常渲染。注意对齐样式在不同工具中的表现差异。\\n\\n**测试 2：换行规则**\\n\\n```markdown\\n第一行\\n第二行\\n\\n第一行\\n\\n第二行\\n```\\n\\n👉 在 CommonMark Dingus 中，直接换行会被合并为空格。在 GFM 中，直接换行会变为 `<br>`（软换行）。这会导致排版间距完全不同。\\n\\n**测试 3：删除线**\\n\\n```markdown\\n~~这段文字被删除了~~\\n```\\n\\n👉 CommonMark Dingus 中显示为普通文本 `~~...~~`。GFM 和 markdown-it（开启 GFM 模式）中会渲染为带删除线的文本。\\n\\n**测试 4：任务列表**\\n\\n```markdown\\n- [x] 已完成\\n- [ ] 未完成\\n```\\n\\n👉 CommonMark Dingus 中 `[x]` 被当作普通文本。GFM 中渲染为可交互的 checkbox。\\n\\n**测试 5：数学公式**\\n\\n```markdown\\n行内公式 $E = mc^2$\\n\\n块级公式：\\n\\n$$\\n\\\\int_{-\\\\infty}^{\\\\infty} e^{-x^2} dx = \\\\sqrt{\\\\pi}\\n$$\\n```\\n\\n👉 CommonMark Dingus 中 `$...$` 原样输出。GFM 会识别并用 `<code>` 包裹。大多数在线工具需要安装插件才能正确渲染数学公式。\\n\\n**测试 6：原始 HTML**\\n\\n```markdown\\n<div style=\\"color: red\\">红色文字</div>\\n\\n<span style=\\"color: blue\\">蓝色</span>\\n```\\n\\n👉 CommonMark 和 GFM 中块级 HTML 保持原样，行内 HTML 会被 `<p>` 包裹。部分工具（如某些富文本编辑器）会过滤掉原始 HTML。\\n\\n**测试 7：标题锚点**\\n\\n```markdown\\n## 我的标题\\n[跳转](#我的标题)\\n```\\n\\n👉 在 GFM 中，标题会自动生成锚点 ID，但通常带有 `user-content-` 前缀。在 markdown-it 中，锚点 ID 直接使用标题文本。你可以查看页面 HTML 源码观察差异。\\n\\n### 关键差异速查表\\n\\n| 特性 | CommonMark | GFM | markdown-it（默认） | TipTap |\\n|------|-----------|-----|-------------------|--------|\\n| 表格 | ❌ 不渲染 | ✅ 原生 | ❌ 需插件 | ✅ 节点序列化 |\\n| 删除线 | ❌ 原样 | ✅ `<del>` | ❌ 需插件 | ✅ Input Rule |\\n| 任务列表 | ❌ 原样 | ✅ checkbox | ❌ 需插件 | ✅ 扩展节点 |\\n| 换行规则 | 合并为空格 | 变 `<br>` | 合并为空格 | 键盘事件 |\\n| 原始 HTML | ✅ 允许 | ✅ 允许 | ✅ 可关闭 | ❌ 屏蔽 |\\n| 数据存储 | Markdown 文本 | Markdown 文本 | Markdown 文本 | JSON 节点树 |\\n\\n## 五、跨规范保持一致的实战建议\\n\\n### 1. 以 CommonMark 为基础，谨慎使用扩展语法\\n\\nCommonMark 是所有现代 Markdown 渲染器的基础。如果你的内容需要在多个平台发布，**优先使用 CommonMark 核心语法**，只在确定目标平台支持时才使用扩展语法。\\n\\n**推荐做法**：\\n\\n````\\n# ✅ 通用语法（CommonMark 安全）\\n\\n**加粗**\\n*斜体*\\n`行内代码`\\n> 引用\\n\\n```python\\n# 围栏代码块\\nprint(\\"hello\\")\\n```\\n\\n- 无序列表\\n1. 有序列表\\n\\n[链接](https://example.com)\\n![图片](image.png)\\n\\n---\\n\\n# ⚠️ 条件使用（确认平台支持）\\n\\n| 表格 | 语法 |\\n| ---- | ---- |\\n\\n- [ ] 任务列表\\n\\n~~删除线~~\\n\\n> [!note] Callout\\n````\\n\\n### 2. 表格：使用最简语法\\n\\n表格是跨平台兼容性最差的语法之一。建议：\\n\\n- **前后保留空行**（兼容性最好）\\n- **使用管道表（Pipe Table）**，这是最广泛支持的表格语法\\n- **不要依赖对齐功能**，很多平台不支持\\n- **表格内容保持简洁**，避免在表格中使用复杂 Markdown\\n\\n```markdown\\n<!-- ✅ 推荐的跨平台表格写法 -->\\n\\n| 名称 | 版本 | 说明 |\\n| --- | --- | --- |\\n| CommonMark | 0.31 | 标准化规范 |\\n| GFM | 1.0 | GitHub 扩展 |\\n```\\n\\n### 3. 图片：使用图床 + 相对路径双保险\\n\\n对于需要跨平台发布的场景：\\n\\n- **使用图床**（如 GitHub 仓库、阿里云 OSS、Cloudflare R2 等）存放图片\\n- **在 Markdown 中使用完整 URL**，而不是相对路径\\n- **如果必须用相对路径**，确保所有平台对路径的解析规则一致\\n\\n```markdown\\n<!-- ✅ 跨平台最安全 -->\\n![示意图](https://cdn.example.com/images/diagram.png)\\n\\n<!-- ⚠️ 仅在特定平台有效 -->\\n![示意图](./images/diagram.png)\\n```\\n\\n### 4. 数学公式：使用 `$$` 块级语法\\n\\n如果需要在支持数学公式的平台间迁移：\\n\\n- **使用 `$$...$$` 块级语法**，比 `$...$` 歧义更少\\n- **避免在行内使用 `$...$`**，除非确定目标平台支持\\n- **考虑使用图片替代复杂公式**，作为兜底方案\\n\\n```markdown\\n<!-- ✅ 推荐的数学公式写法 -->\\n\\n$$\\nE = mc^2\\n$$\\n\\n<!-- ⚠️ 行内公式可能被误解 -->\\n行内公式 $E = mc^2$ 在某些平台会失效。\\n```\\n\\n### 5. 脚注：使用替代方案\\n\\n由于脚注在 GFM 和 CommonMark 中不支持，建议：\\n\\n- **使用行内括号注释**代替脚注：`（详见附录 A）`\\n- **使用超链接**代替脚注引用：`[详见此文](https://example.com)`\\n- **在文末统一用列表列出参考信息**\\n\\n```markdown\\n<!-- ✅ 跨平台替代方案 -->\\n这是一段需要说明的文字（详见参考资料[1]）。\\n\\n---\\n\\n**参考资料：**\\n\\n[1] Markdown 规范文档，https://spec.commonmark.org\\n```\\n\\n### 6. 删除线：用文字表达代替\\n\\n```markdown\\n<!-- ❌ 不跨平台 -->\\n~~这个功能已废弃~~\\n\\n<!-- ✅ 跨平台 -->\\n<del>这个功能已废弃</del>（已废弃）\\n```\\n\\n使用 `<del>` HTML 标签比 `~~` 语法兼容性更好，因为几乎所有 Markdown 渲染器都允许内联 HTML。\\n\\n### 7. 任务列表：用列表 + 文字代替\\n\\n```markdown\\n<!-- ❌ 不跨平台 -->\\n- [x] 已完成\\n- [ ] 未完成\\n\\n<!-- ✅ 跨平台 -->\\n- ✅ 已完成\\n- ⬜ 未完成\\n```\\n\\n使用 Emoji 符号代替任务列表的复选框，在所有平台上都能正确显示。\\n\\n### 8. 换行：统一使用空行分段\\n\\n```markdown\\n<!-- ✅ 跨平台推荐 -->\\n这是第一段。\\n\\n这是第二段，与第一段之间有空行。\\n\\n<!-- ❌ 行为不一致 -->\\n这是第一行。\\n这是第二行，在 GFM 中会换行，在 CommonMark 中不会。\\n```\\n\\n**最佳实践**：段落之间始终使用空行分隔。需要换行但不分段时，使用 `<br>` HTML 标签。\\n\\n### 9. 使用标准化工具进行检测\\n\\n推荐使用以下工具来检查 Markdown 的兼容性：\\n\\n- **[markdownlint](https://github.com/DavidAnson/markdownlint)**：VS Code 插件，可配置规则检查 CommonMark 兼容性\\n- **[remark-lint](https://github.com/remarkjs/remark-lint)**：基于 remark 的 Markdown 检查工具\\n- **[CommonMark 规范测试](https://spec.commonmark.org/dingus/)**：在线测试你的 Markdown 是否符合 CommonMark 规范\\n\\n**推荐的 markdownlint 配置**：\\n\\n```json\\n{\\n  \\"MD001\\": true,\\n  \\"MD003\\": { \\"style\\": \\"atx\\" },\\n  \\"MD007\\": { \\"indent\\": 2 },\\n  \\"MD009\\": false,\\n  \\"MD012\\": true,\\n  \\"MD022\\": true,\\n  \\"MD024\\": false,\\n  \\"MD026\\": false,\\n  \\"MD032\\": true,\\n  \\"MD033\\": false,\\n  \\"MD036\\": false,\\n  \\"MD041\\": false\\n}\\n```\\n\\n### 10. 建立自己的 Markdown 风格指南\\n\\n对于团队或个人长期维护的内容，建议建立一份 Markdown 风格指南，明确：\\n\\n1. **标题**：使用 ATX 风格（`#`）还是 Setext 风格（`===`）？推荐 ATX。\\n2. **列表**：无序列表使用 `-`、`*` 还是 `+`？推荐 `-`。\\n3. **代码块**：使用围栏代码块，标注语言。\\n4. **图片**：统一使用图床 URL。\\n5. **表格**：使用管道表，前后空行。\\n6. **引用**：每行一个 `>` 还是只在段落开头使用？推荐每行一个。\\n7. **空行**：块级元素前后保留空行。\\n\\n## 六、总结\\n\\nMarkdown 的碎片化是一个历史遗留问题，短期内不可能完全解决。但作为内容创作者，我们可以通过以下策略来应对：\\n\\n| 策略 | 适用场景 | 成本 |\\n|------|---------|------|\\n| **以 CommonMark 为子集** | 多平台通用内容 | 低，但功能受限 |\\n| **为目标平台定制** | 单平台发布 | 低，但不可迁移 |\\n| **使用抽象层工具** | 多平台发布 | 中，需额外工具 |\\n| **建立风格指南 + 自动化检查** | 团队协作 | 中高，但长期收益大 |\\n\\n对于大多数场景，我的建议是：\\n\\n1. **核心内容用 CommonMark 语法**，确保在任何平台都能正确显示\\n2. **扩展语法加注释标记**，方便在特定平台发布时做转换\\n3. **使用图床管理图片**，避免路径问题\\n4. **用 CI/CD 工具做格式检查**，在提交前发现兼容性问题\\n5. **如果使用大模型生成 Markdown**，在 Prompt 中明确指定目标规范\\n\\n最后，记住一个原则：**Markdown 的初衷是\\"易读易写\\"，而不是\\"功能丰富\\"**。当你在某个炫酷的扩展语法和跨平台兼容性之间犹豫时，问问自己：这个语法真的让内容更好读了吗？还是只是让渲染效果更花哨？\\n\\n毕竟，Markdown 之所以能成为大模型的\\"第二语言\\"，正是因为它足够简单、足够通用。保持简单，就是保持力量。\\n\\n","lastUpdated":1783064727487},{"title":"利用github的pages服务搭建个人主页第三篇-评论和图片预览篇","content":"# 利用github的pages服务搭建个人主页第三篇-giscus评论组件和图片预览\\n\\n上一篇文章[利用github的pages服务搭建个人主页第二篇-主题配置](https://www.codemyhappy.com/blog/利用github的pages服务搭建个人主页第二篇-主题配置)，教大家美化了主页的样式。\\n\\n这一篇文章介绍如何使用giscus组件来添加评论功能，并且添加图片预览功能。\\n\\n## 评论功能\\n\\n### 原理\\n\\ngiscus 加载时，会使用 GitHub Discussions 搜索 API 根据选定的映射方式（如 URL、pathname、title等）来查找与当前页面关联的 discussion。如果找不到匹配的 discussion，giscus bot 就会在第一次有人留下评论或回应时自动创建一个 discussion。\\n\\n### 第一步：找到giscus的官网\\n\\n官网地址： [https://giscus.app/zh-CN](https://giscus.app/zh-CN)\\n\\n按照giscus官网的步骤，配置项目仓库就行了。\\n\\n它还贴心的有一个检测功能，能检测你的项目仓库是否满足要求。\\n\\n![alt text](blog-imgs/利用github的pages服务搭建个人主页第三篇-评论和图片预览篇/image.png)\\n\\n### 第二步：在本项目中集成giscus\\n\\n官方默认的方式是使用script标签引入giscus。\\n\\n![alt text](blog-imgs/利用github的pages服务搭建个人主页第三篇-评论和图片预览篇/image-1.png)\\n\\n并且我试用了一下官方的vue库，并不能适配我的这个项目。\\n\\n于是就自己写了个组件，如下：\\n\\n```vue\\n<script setup>\\n// .vitepress/theme/GiscusComment.js\\nimport { onMounted, ref } from \'vue\';\\n\\nconst commentState = ref(1)\\n\\nonMounted(()=>{\\n  const script = document.createElement(\'script\');\\n  script.src = \'https://giscus.app/client.js\';\\n  script.async = true;\\n  script.crossOrigin = \'anonymous\';\\n  script.setAttribute(\'data-repo\', \'codemyhappy/codemyhappy.github.io\');\\n  script.setAttribute(\'data-repo-id\', \'R_kgDOIr5QXA\');\\n  script.setAttribute(\'data-category\', \'Announcements\');\\n  script.setAttribute(\'data-category-id\', \'DIC_kwDOIr5QXM4C_T_S\');\\n  script.setAttribute(\'data-mapping\', \'pathname\');\\n  script.setAttribute(\'data-strict\', \'0\');\\n  script.setAttribute(\'data-reactions-enabled\', \'1\');\\n  script.setAttribute(\'data-emit-metadata\', \'0\');\\n  script.setAttribute(\'data-input-position\', \'top\');\\n  script.setAttribute(\'data-theme\', \'preferred_color_scheme\');\\n  script.setAttribute(\'data-lang\', \'zh-CN\');\\n  document.getElementById(\'code-my-happy-giscus-comment\').appendChild(script);\\n  script.onload = function () {\\n    console.log(\'giscus loaded\');\\n    commentState.value = 3;\\n  };\\n  script.onerror = function () {\\n    commentState.value = 2;\\n  };\\n})\\n\\n<\/script>\\n\\n<template>\\n  <div>\\n      {{ commentState===1 ? \'评论加载中...\' : \'\' }}\\n      {{ commentState===2 ? \'评论组件加载失败，刷新重试一下吧\' : \'\' }}\\n      <div id=\\"code-my-happy-giscus-comment\\"></div>\\n  </div>\\n</template>\\n```\\n\\n然后，插入到theme的文章底部就行了。\\n\\n```js\\n// .vitepress/theme/index.js\\nimport { h } from \'vue\'\\nimport DefaultTheme from \'vitepress/theme\'\\nimport GiscusComment from \'./GiscusComment.vue\'\\n\\nexport default {\\n  extends: DefaultTheme,\\n  Layout() {\\n    return h(DefaultTheme.Layout, null, {\\n        // 将组件插入到文章的底部\\n      \'doc-after\': () => h(GiscusComment)\\n    })\\n  }\\n}\\n```\\n\\n### 最后，测试评论一下\\n\\n![alt text](blog-imgs/利用github的pages服务搭建个人主页第三篇-评论和图片预览篇/image-2.png)\\n\\n至此，大功告成！评论组件就做好了。\\n\\n想看源码的朋友自己去看吧！\\n\\n源码位置：[GiscusComment.vue](https://github.com/codemyhappy/codemyhappy.github.io/blob/main/.vitepress/theme/GiscusComment.vue)\\n\\n\\n## 图片预览功能\\n\\n图片预览功能，我看了几个库，选了一个最轻量级的`medium-zoom`，gzip大小只有3KB！\\n\\n它的体验非常丝滑，自己去它的官网体验吧。\\n\\nhttps://medium-zoom.francoischalifour.com/\\n\\n![alt text](blog-imgs/利用github的pages服务搭建个人主页第三篇-评论和图片预览篇/image-3.png)\\n\\n接入步骤也很简单，基本跟着官网的步骤，安装和配置就行了。\\n\\n### 第一步：安装medium-zoom\\n```bash\\npnpm install medium-zoom\\n```\\n\\n### 第二步：封装个空组件\\n\\n空组件的作用就是放到文档最底部，这样图片加载完成之后，就可以触发图片预览功能了。\\n\\n```vue\\n<script setup>\\n// file: .vitepress/theme/ImagePreview.vue\\nimport mediumZoom from \'medium-zoom\'\\nimport { onMounted } from \'vue\';\\n\\nonMounted(() => {\\n  mediumZoom(\'img\',{\\n    background: \'#000\',\\n    container: document.body,\\n  })\\n})\\n<\/script>\\n\\n<template>\\n\\n</template>\\n\\n<style>\\n.medium-zoom-overlay{\\n    z-index: 9999999;\\n}\\n.medium-zoom-image--opened{\\n    z-index: 99999999;\\n}\\n\\n.content img{\\n    box-shadow:  1px 1px 6px rgba(0,0,0,.2), -1px -1px 6px rgba(0,0,0,.2);\\n    border-radius: 8px;\\n    max-width: 400px;\\n    margin: 0 auto;\\n}\\n</style>\\n```\\n\\n里面有些CSS样式，是为了增加图片的体验的。加了些阴影、改了层级，其他没动。\\n\\n### 第三步：在theme的index.js中引入\\n\\n新建一个容器组件，把评论组件和图片预览组件，两个都插入到容器组件中。\\n\\n```vue\\n<script setup>\\n// file: .vitepress/theme/CodeMyHappyTheme.vue\\nimport GiscusComment from \'./GiscusComment.vue\';\\nimport ImagePreview from \'./ImagePreview.vue\';\\n<\/script>\\n\\n<template>\\n    <ImagePreview/>\\n    <GiscusComment/>\\n</template>\\n```\\n\\n最后引入到index.js中\\n```js\\n// file: .vitepress/theme/index.js\\nimport { h } from \'vue\'\\nimport DefaultTheme from \'vitepress/theme\'\\nimport CodyMyHappyTheme from \'./CodyMyHappyTheme.vue\'\\n\\nexport default {\\n  extends: DefaultTheme,\\n  Layout() {\\n    return h(DefaultTheme.Layout, null, {\\n      \'doc-after\': () => h(CodyMyHappyTheme)\\n    })\\n  }\\n}\\n```\\n\\n整个配置就完成了！\\n简单测试一下吧。\\n\\n下面这张图是个测试图片，点它就可以预览啦！\\n![alt text](blog-imgs/利用github的pages服务搭建个人主页第三篇-评论和图片预览篇/image-3.png)\\n\\n至此，图片预览功能也完成了！\\n\\n想看源码的朋友自己去看吧！\\n\\n源码位置：[ImagePreview.vue](https://github.com/codemyhappy/codemyhappy.github.io/blob/main/.vitepress/theme/ImagePreview.vue)\\n\\n## 总结\\n\\n本篇是利用github的pages服务搭建个人主页的完结篇。\\n\\n加入了图片预览功能和评论功能。\\n\\n**回顾整个流程，总共就三篇：**\\n\\n- 第一篇，教大家开通了GitHub Pages，能访问到自己的主页。[去查看->](https://codemyhappy.github.io/blog/%E5%A6%82%E4%BD%95%E5%88%A9%E7%94%A8github%E7%9A%84pages%E6%9C%8D%E5%8A%A1%E6%90%AD%E5%BB%BA%E4%B8%80%E4%B8%AA%E4%B8%AA%E4%BA%BA%E4%B8%BB%E9%A1%B5.html)\\n\\n- 第二篇，教大家如何美化自己的主页。 [去查看->](https://codemyhappy.github.io/blog/%E5%A6%82%E4%BD%95%E5%88%A9%E7%94%A8github%E7%9A%84pages%E6%9C%8D%E5%8A%A1%E6%90%AD%E5%BB%BA%E4%B8%80%E4%B8%AA%E4%B8%AA%E4%BA%BA%E4%B8%BB%E9%A1%B5%E7%AC%AC%E4%BA%8C%E7%AF%87-%E7%BE%8E%E5%8C%96%E7%AF%87.html)\\n\\n- 第三篇，教大家如何添加评论功能和图片预览功能。[去查看->](https://codemyhappy.github.io/blog/%E5%88%A9%E7%94%A8github%E7%9A%84pages%E6%9C%8D%E5%8A%A1%E6%90%AD%E5%BB%BA%E4%B8%AA%E4%BA%BA%E4%B8%BB%E9%A1%B5%E7%AC%AC%E4%B8%89%E7%AF%87-%E8%AF%84%E8%AE%BA%E5%92%8C%E5%9B%BE%E7%89%87%E9%A2%84%E8%A7%88%E7%AF%87.html)\\n\\n目前这些对于我来说就够用了。\\n\\n如果大家还有其他需要的功能，可以在评论区进行许愿，我会尽快添加的。\\n\\n","lastUpdated":1781774278625},{"title":"index","content":"---\\nlayout: home\\n\\n---\\n\\n<script setup lang=\\"ts\\">\\nimport BlogList from \'../components/BlogList.vue\'\\n\\n<\/script>\\n\\n\\n# 博客\\n\\n这是我的技术博客页面，记录了我的编程经验、技术思考和项目实践。\\n\\n这里的内容会自动更新，请持续关注。\\n\\n## 文章列表\\n\\n<BlogList/>","lastUpdated":1781746819372},{"title":"如何利用github的pages服务搭建一个个人主页第二篇-美化篇","content":"# 如何利用github的pages服务搭建一个个人主页-第二篇-美化篇\\n\\n在[上一篇文章](如何利用github的pages服务搭建一个个人主页.md)中，我们介绍了如何使用GitHub Pages搭建一个最简单的个人主页，但那个主页确实比较简陋，没有太多内容，没有美化、没有导航栏、大纲、没有自动化构建。今天我们来聊聊如何让我们的个人主页变得更美观、更实用。\\n\\n## 回顾：开启GitHub Pages服务\\n\\n还记得吗？在上篇中，我们通过以下步骤开启了GitHub Pages服务：\\n1. 创建了名为 `{username}.github.io` 的特殊仓库\\n2. 在仓库的 Settings > Pages 中配置了部署源\\n3. 将内容放在 `/docs` 目录下进行部署\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页第二篇-美化篇/image.png)\\n\\n## 美化方案\\n\\n对于美化个人主页，我这里推荐两种方案：\\n\\n### 小白方案-基于Publii\\n\\nPublii 是一款免费的桌面应用程序，专为创建静态网站而设计。它具有直观的界面和强大的功能，即使没有编码经验的人也能轻松使用。\\n\\n**优点：**\\n- 可视化编辑器，像编辑Word文档一样简单\\n- 预设的主题模板\\n- 无需代码知识\\n\\n**缺点：**\\n- 功能相对有限\\n- 定制化程度不如手写代码高\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页第二篇-美化篇/image-1.png)\\n\\n### 折腾方案-基于VitePress\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页第二篇-美化篇/image-2.png)\\n\\n这正是我现在使用的方式，也是我个人推荐的方案。VitePress 是一个极简的静态站点生成器，由 Vue.js 和 Vite 驱动。\\n\\n我已将我的个人主页开源，你可以直接使用我的模板，详情请查看项目 README：\\n\\n地址：[https://github.com/codemyhappy/codemyhappy.github.io](https://github.com/codemyhappy/codemyhappy.github.io)\\n\\n#### 基本使用方法\\n\\n> 需要下载[Node.js](https://nodejs.org/en/) 和[git客户端](https://git-scm.com/)\\n> \\n> 两个工具的安装都是傻瓜式的，请自行安装\\n\\n\\n1. **克隆我的项目**\\n   ```bash\\n   git clone https://github.com/codemyhappy/codemyhappy.github.io.git\\n   cd codemyhappy.github.io\\n   ```\\n\\n2. **安装依赖**（需要先安装pnpm）\\n   ```bash\\n   npm install -g pnpm\\n   pnpm install\\n   ```\\n\\n3. **启动开发服务器**\\n   ```bash\\n   pnpm dev\\n   ```\\n   然后访问 `http://localhost:9002` 查看效果\\n\\n4. **更换远程仓库地址**\\n   ```bash\\n   # 删除原始的远程仓库地址\\n   git remote remove origin\\n   \\n   # 添加你自己的仓库地址 (将 {your_username} 替换为你的 GitHub 用户名)\\n   git remote add origin https://github.com/{your_username}/{your_username}.github.io.git\\n   ```\\n\\n5. **推送代码到你的仓库**\\n   ```bash\\n   # 推送 main 分支\\n   git push -u origin main\\n   ```\\n\\n部署过程中会自动生成静态文件，并推送到GitHub Pages。\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页第二篇-美化篇/image-3.png)\\n\\n#### 项目目录结构\\n\\n```\\n.\\n├── .vitepress/             # VitePress 配置目录\\n├── wwwroot/                # 源代码目录 (VitePress 源文件)\\n│   ├── blog/               # 博客文章目录\\n│   │   ├── index.md        # 博客首页\\n│   │   └── 文章文件...\\n│   ├── index.md            # 首页\\n│   └── public/             # 静态资源目录\\n├── docs/                   # 构建输出目录 (GitHub Pages 部署目录)\\n├── todo-drafts/            # 待发布文章草稿\\n├── components/             # 博客组件目录\\n├── deploy.sh               # 自动化部署脚本\\n├── push-to-remote.sh       # 仅推送到远程仓库，不发版\\n├── package.json            # 项目配置和脚本\\n└── README.md               # 项目说明\\n```\\n\\n具体的开发流程、更多脚本命令和部署方式，请参阅项目根目录的 README.md 文件，里面有详细的说明。\\n\\n## 总结\\n\\n静态网站生成器有很多，如Hexo、Jekyll、Hugo、Astro，等等。\\n\\n但我这个项目基于Vitepress在背后做了许多的工作，比如自动生成目录、自动生成侧边栏、自动生成导航栏等等。\\n\\n当然，如果你只是想要一个非常简单的页面，使用纯HTML/CSS也是可以的。选择哪种方案取决于你的需求和技术水平。\\n\\n\\n## 最后预告一下\\n\\n这篇文章是github搭建静态主页，系列文章的第二篇，下一篇文章我计划新增评论功能和图片放大功能。\\n\\n希望这篇文章能帮助你搭建出一个满意的个人主页！如果你有任何问题，欢迎在评论区交流。\\n","lastUpdated":1781660557369},{"title":"chrome-devtools-protocol，别名CDP，浏览器自动化知识储备","content":"# chrome-devtools-protocol，别名CDP，浏览器自动化知识储备\\n\\n## 储备的一些学习链接，等我有空再看\\n\\n- [getting-started-with-cdp](https://github.com/aslushnikov/getting-started-with-cdp/blob/master/README.md)\\n\\n这是一篇cdp底层的介绍文章，通过socket连接cdp，给cdp发送和接收底层的消息。\\n\\n\\n- [chromedevtools.github.io/devtools-protocol/](https://chromedevtools.github.io/devtools-protocol/)\\n\\n这是chrome官方的cdp文档，仅仅是个文档，没有教程。\\n\\n- [基于CDP的命令行工具 - opencli](https://opencli.info/docs/)\\n\\n这是一个基于cdp的命令行工具，它的目标是通过cdp将网站变为command命令。\\n\\n- [基于CDP的高级API - Chrome DevTools 团队维护的Puppeteer](https://github.com/puppeteer/puppeteer)\\n\\n这是一个基于cdp的高级API，类似于模拟一个浏览器，基于puppeteer可开发很多浏览器自动化项目。\\n\\n- [如何打开浏览器的CDP监控面板](https://developer.chrome.google.cn/docs/devtools/protocol-monitor?hl=zh-cn)\\n\\n这是一个打开chrome浏览器自带的cdp监控面板，可以查看所有cdp的请求和响应。\\n\\n- [适配器func中page的类型定义，是一个非标准的Puppeteer类型](https://github.com/jackwener/OpenCLI/blob/main/src/types.ts)\\n\\n这是opencli开发adapter的一个类型定义，opencli的adapter开发的文档非常少，这个类型是从其源码中找到的。","lastUpdated":1781659724170},{"title":"macOS安装whisper进行语音识别","content":"macOS安装whisper进行语音识别.md\\n---\\ntitle: 在 macOS 上安装 Whisper 进行语音识别\\n---\\n<!-- ![alt text](blog-imgs/macOS安装whisper进行语音识别/image.png) -->\\n\\n# 在 macOS 上安装 Whisper 进行语音识别\\n\\n## 第一步：安装 Homebrew\\n\\nHomebrew 是一个开源的软件包管理工具，非常适合在 macOS 系统上使用。\\n\\n> 如果您已经安装了 Homebrew，可以跳过此步骤。\\n\\n### 安装过程\\n\\n1. 访问 [Homebrew 官网](https://brew.sh/)\\n2. 复制官网提供的安装命令\\n3. 粘贴到终端中并回车执行\\n\\n![alt text](blog-imgs/macOS安装whisper进行语音识别/image-2.png)\\n\\n> **注意**：下载过程可能比较耗时，请耐心等待。\\n\\n### 配置环境变量\\n\\n安装完成后，您需要配置环境变量，否则执行命令时可能会报错。\\n\\n配置环境变量很简单，只需执行终端提示的脚本命令即可：\\n\\n![alt text](blog-imgs/macOS安装whisper进行语音识别/image-3.png)\\n\\n执行完成后，您就可以正常使用 brew 命令了。\\n\\n> 成功完成此步骤后，整个安装过程就完成了一大半。\\n\\n## 第二步：下载 Whisper 的语音模型\\n\\n官方提供了 tiny、base、small、medium、large 五种不同规格的语音模型。\\n\\n| 模型 | 适用场景 | 特点 |\\n|------|----------|------|\\n| tiny | 快速测试 | 最小 |\\n| base | 一般用途 | 小巧 |\\n| small | 一般用途 | 推荐 |\\n| medium | 高精度需求 | 较大 |\\n| large | 最高精度 | 最大 |\\n\\n对于一般用途，推荐选择 **small** 模型。虽然只有几百 MB，但中文识别准确度很高。\\n\\n### 下载模型\\n\\n1. 访问 Whisper 模型下载页面 (例如 [huggingface.co/ggerganov/whisper.cpp](https://huggingface.co/ggerganov/whisper.cpp))\\n2. 找到 `ggml-small.bin` 文件\\n3. 点击下载\\n\\n下载完成后，请将模型文件保存在一个容易访问的目录中备用。\\n\\n![alt text](blog-imgs/macOS安装whisper进行语音识别/image-1.png)\\n\\n\\n\\n## 第三步：安装 Whisper\\n\\n由于我们之前安装了 Homebrew，现在只需执行以下命令即可完成安装：\\n\\n```bash\\nbrew install whisper-cpp\\n```\\n\\n> **注意**：安装过程中可能会出现网络问题，可以重试或尝试使用代理。\\n\\n## 如何使用 Whisper\\n\\nWhisper 官方提供了多种使用方式，下面介绍一种最简单的用法：**whisper-server**。\\n\\n### 启动 Whisper Server\\n\\nwhisper-server 是官方自带的可视化界面，可以直接在浏览器中打开，操作方便。\\n\\n执行以下命令启动服务：\\n\\n```bash\\nwhisper-server --model /Users/happy/code/playground/whisper.cpp/models/ggml-small.bin --language zh --port 9001 --prompt \\"请使用简体中文输出文字\\"\\n```\\n\\n> **重要**：请将命令中的 `/Users/happy/code/playground/whisper.cpp/models/ggml-small.bin` 替换为您在第二步中下载的语音模型文件的实际路径。\\n\\n例如，如果您的模型文件保存在 Downloads 文件夹中：\\n\\n```bash\\nwhisper-server --model /Users/happy/Downloads/ggml-small.bin --language zh --port 9001 --prompt \\"请使用简体中文输出文字\\"\\n```\\n\\n### 启动命令中参数的含义\\n\\n- --model：指定模型文件路径\\n- --language：指定语言\\n- --port：指定服务端口\\n- --prompt：指定提示语，让它输出简体中文，不然默认为繁体中文\\n\\n\\n### 使用界面\\n\\n命令执行成功后，服务会监听端口 **9001**。\\n\\n在浏览器中打开 `http://localhost:9001` 即可看到界面。\\n\\n![alt text](blog-imgs/macOS安装whisper进行语音识别/image-4.png)\\n\\n界面非常简洁，您需要做的所有事情包括：\\n\\n1. 选择一个语音文件\\n2. 选择需要的文件输出格式\\n3. 点击 **Submit** 按钮\\n\\n### 输出格式选项\\n\\nWhisper 支持多种输出格式：\\n\\n- **TXT** - 纯文本格式\\n- **VTT** - WebVTT 字幕格式\\n- **SRT** - 标准字幕格式\\n- **JSON** - JSON 格式\\n\\n## 与视频编辑软件结合\\n\\n生成的字幕文件可以导入到各种视频编辑软件中，例如剪映：\\n\\n1. 导出 SRT 字幕文件\\n2. 打开视频编辑软件（如剪映）\\n3. 导入音频文件\\n4. 导入生成的字幕文件\\n5. 调整字幕样式和位置\\n\\n\\n## 总结\\n\\n这种使用 Whisper 生成字幕的方法具有以下优点：\\n\\n- **免费**：无需付费使用\\n- **准确**：中文识别准确率高\\n- **灵活**：支持多种输出格式\\n- **高效**：处理速度快\\n\\n这种方式完美解决了普通用户自动生成字幕的需求。如果您觉得这个方法有用，请点赞关注我，我会持续分享更多实用技巧。\\n\\n## 常见问题\\n\\n### Q: 安装过程中遇到网络问题怎么办？\\n\\nA: 可以尝试重试，或使用网络加速工具。\\n\\n### Q: 模型文件应该选择哪个？\\n\\nA: 对于一般用途，推荐 small 模型；对精度要求高可选择 medium 或 large。\\n\\n### Q: 如何提高识别准确度？\\n\\nA: 选择更大的模型，或对原始音频进行降噪处理。","lastUpdated":1781659724170},{"title":"串流经验分享，sunshine加moonlight串流，实战教学","content":"# 串流经验分享，sunshine加moonlight串流，实战教学\\n\\n本篇介绍串流经验分享，记录串流经验，以及串流过程中遇到的问题。\\n\\n## 软件安装\\n\\n### sunshine安装\\n\\n### moonlight安装\\n\\n## 串流步骤\\n\\n1. 启动sunshine\\n2. 启动moonlight\\n3. PC和移动端连接同一个wifi\\n4. moonlight客户端会自动搜索到sunshine，点击即可串流\\n\\n## 问题汇总\\n\\n### 帧率上不去基本都是30fps\\n\\nsunshine配置项中，设置最小目标帧率，90或者120，视情况而定。\\n\\n### 控制端无法使用模拟的手柄\\n\\nwindows的PC端需要安装ViGEmBus驱动。\\n\\n### moonlight客户端声音断断续续、出现破音\\n\\n我的场景是PC和pad都连5G的WiFi，声音破音。\\n\\n换成2.4G网络，或者PC端直接插网线，问题就解决了。\\n\\n### moonlight默认虚拟的手柄不好用\\n\\nmoonlight的安卓端虚拟的手柄太难用了，暂时未解决。","lastUpdated":1781659724170},{"title":"关于我","content":"# 关于我\\n\\n## 个人简介\\n\\n当过小兵，做过管理；敲过代码，写过文档；进过大厂，蹲过作坊。身经百战，一切都是沉淀，关注我，希望我的分享对你有所帮助！\\n\\n我一直热衷于探索技术的可能性，特别是前端开发和Web应用领域。在多年的从业经历中，我经历了各种不同类型项目的锤炼，从小型创业公司的敏捷开发到大型企业的复杂系统建设，这些经历让我积累了丰富的实践经验。\\n\\n## 联系方式\\n\\n- [小红书主页](https://www.xiaohongshu.com/user/profile/610e50bd00000000010088fd)\\n- [GitHub主页](https://github.com/codemyhappy)\\n- [CSDN主页](https://blog.csdn.net/qq_21197033)\\n- [个人博客](https://codemyhappy.github.io/)\\n\\n## 博客简介\\n\\n专注前端、专注互联网、分享原创的技术博客。\\n\\n我的博客是我多年学习和实践的心得总结，涵盖了前端技术、互联网思考以及软件开发的最佳实践。在这里，我会分享最新的技术趋势解读、实用的开发技巧以及项目实战经验。\\n\\n## 个人项目作品\\n\\n以下是我在个人时间里开发的一些有趣项目：\\n\\n### 微信小游戏《别踩白块》\\n一款经典的休闲小游戏，考验玩家的反应速度和节奏感。使用微信小程序技术开发，界面简洁，玩法上瘾。\\n\\n> 提示：此处需要添加项目截图\\n\\n### VSCode插件《blog-publisher-for-all》\\n一款强大的Markdown多平台发布工具，支持一键发布到多个博客平台。解决了技术写作者需要多平台同步内容的痛点。\\n\\n> 提示：此处需要添加插件界面截图\\n\\n### 2D渲染引擎：ycc.js\\n一个轻量级的2D图形渲染引擎，适用于游戏开发和图形应用。该引擎具有高性能、易用性和可扩展性的特点。\\n\\n> 提示：此处需要添加引擎演示图\\n\\n### 本地服务管理工具《minebook-hot-server》\\n便捷的本地服务管理工具，简化开发过程中的服务器启动和管理流程，特别适合前端开发者的日常使用。\\n\\n> 提示：此处需要添加工具界面截图\\n\\n## 技术专长\\n\\n- **前端技术**: JavaScript, Vue, React, CSS, HTML, Webpack\\n- **后端技术**: Node.js, Python, 数据接口设计\\n- **移动开发**: 微信小程序, Hybrid应用\\n- **工具开发**: VSCode插件, 开发效率工具\\n- **项目管理**: 敏捷开发, 团队协作, 流程优化\\n\\n## 学习与分享\\n\\n我相信技术的价值在于分享和传播，所以我会持续在我的博客上更新技术文章和项目经验。如果你觉得我的内容对你有帮助，请关注我的各个社交媒体账号，一起交流技术心得！","lastUpdated":1781659724170},{"title":"如何利用github的pages服务搭建一个个人主页","content":"# 如何利用GitHub的Pages服务搭建个人网站\\n\\nGitHub Pages是一个免费的静态网站托管服务，可以让你轻松地从GitHub仓库托管网站。本文将详细介绍如何使用GitHub Pages搭建一个个人主页。\\n\\n## 准备工作\\n\\n在开始之前，你需要完成以下准备工作：\\n\\n### 1. 注册GitHub账号\\n如果你还没有GitHub账号，需要先注册一个：\\n- 访问 [https://github.com](https://github.com) \\n- 点击\\"Sign up\\"按钮\\n- 按照提示填写必要信息完成注册\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-1.png)\\n\\n### 2. 安装Git工具\\n为了能够与GitHub交互，你还需要在本地安装Git：\\n- 访问 [https://git-scm.com/downloads](https://git-scm.com/downloads)\\n- 下载对应操作系统的版本\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-2.png)\\n\\n\\n安装完成后，在终端运行以下命令验证：\\n\\n```bash\\ngit --version\\n```\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image.png)\\n\\n## Step1、 创建个人主页仓库\\n\\nGitHub Pages有两种类型的站点：项目站点和用户/组织站点。我们这里要创建的是用户站点。\\n\\n### 1. 创建特殊命名的仓库\\nGitHub Pages用户站点需要一个特殊命名的仓库：\\n- 仓库名称必须是 `{username}.github.io`，其中`{username}`是你的GitHub用户名\\n- 例如，如果用户名是`codemyhappy`，那么仓库名应该是`codemyhappy.github.io`\\n\\n### 2. 创建步骤\\n1. 登录GitHub账户\\n2. 点击右上角的\\"+\\"号，选择\\"New repository\\"\\n3. 在仓库名称框中输入 `{username}.github.io`\\n4. 选择\\"Public\\"（公共仓库）\\n5. 勾选\\"Add a README file\\"选项\\n6. 点击\\"Create repository\\"\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-3.png)\\n\\n## Step2、 配置GitHub Pages服务\\n1. 进入你刚刚创建的`{username}.github.io`仓库\\n2. 点击仓库顶部的\\"Settings\\"标签页\\n3. 向下滚动到\\"Pages\\"部分\\n4. 在\\"Source\\"下拉菜单中选择\\"Deploy from a branch\\"\\n5. 在分支选项中选择\\"main\\"分支，并在子目录中选择\\"/docs\\"（这样GitHub Pages会从docs文件夹部署网站）\\n6. 点击\\"Save\\"保存设置\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-4.png)\\n\\n配置完成后，GitHub会自动开始部署你的Pages站点，但目前内容是空白的。\\n\\n## Step3、 添加内容到个人主页\\n### 1. 克隆自己的仓库到本地\\n\\n先找到自己的仓库地址，复制到粘贴板。\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-5.png)\\n\\n然后随便找一个目录，例如我这里的`/Users/happy/code/private_job`，打开终端进入到这个目录。\\n\\n最后执行命令即可：\\n\\n```bash\\ngit clone 你的仓库地址\\n```\\n\\n### 2. 创建基本的HTML文件\\n\\n克隆项目后，在仓库根目录下创建一个docs文件夹。\\n\\n然后在其中创建一个简单页面`index.html`，内容如下:\\n\\n```html\\n<!DOCTYPE html>\\n<html lang=\\"zh-CN\\">\\n<head>\\n  <meta charset=\\"UTF-8\\">\\n  <meta name=\\"viewport\\" content=\\"width=device-width, initial-scale=1.0\\">\\n  <title>我的个人主页</title>\\n</head>\\n<body style=\\"text-align: center; padding-top: 100px;\\">\\n  这是我的个人主页，欢迎你的访问！\\n</body>\\n</html>\\n```\\n\\n预览效果就一个行文字：\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-10.png)\\n\\n\\n### 3. 提交文件到GitHub\\n1. 在本地仓库中创建docs目录\\n2. 将index.html文件放入docs目录\\n3. 提交更改：\\n\\n```bash\\ngit add . && git commit -m \\"初始化\\"\\ngit push origin main\\n```\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-6.png)\\n\\n## 高级定制选项\\n\\n### 1. 使用自定义域名\\n如果你想使用自己的域名而不是github.io的子域名：\\n\\n1. 在DNS提供商处设置CNAME记录指向`{username}.github.io`\\n2. 在GitHub仓库的Settings > Pages部分添加自定义域名\\n3. 在仓库根目录创建CNAME文件，内容为你的域名\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-8.png)\\n\\n### 2. 自定义样式和功能\\n- 通过CSS自定义样式\\n- 使用JavaScript添加交互功能\\n- 引入第三方库和框架\\n\\n比如，我们整一个粉色背景、大号字体的HTML文件：\\n\\n```html\\n<!DOCTYPE html>\\n<html lang=\\"zh-CN\\">\\n<head>\\n  <meta charset=\\"UTF-8\\">\\n  <meta name=\\"viewport\\" content=\\"width=device-width, initial-scale=1.0\\">\\n  <title>我的个人主页</title>\\n  <style>\\n    body {\\n      background-color: pink;\\n      font-size: 32px;\\n      font-weight: bold;\\n    }\\n  </style>\\n</head>\\n<body style=\\"text-align: center; padding-top: 100px;\\">\\n  这是我的个人主页，欢迎你的访问！\\n</body>\\n</html>\\n```\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-9.png)\\n\\n\\n\\n## 进阶：使用静态网站生成器\\n\\n虽然我们可以直接编写HTML文件，但对于内容较多的网站，使用静态网站生成器会更方便。目前有很多静态网站生成器可以选择，比如Hugo、Gatsby、VuePress、VitePress等。\\n\\n在这篇文章中，我们仅介绍了基础的手动创建方式。在下一篇文章中，我将详细介绍如何使用VitePress来搭建一个功能完善的个人博客系统，它更适合用来创建包含多篇文章的技术博客。\\n\\n这是当前我这个博客的目录架构：\\n\\n![alt text](blog-imgs/如何利用github的pages服务搭建一个个人主页/image-7.png)\\n\\n项目细节等我后续连载课程再给大家介绍。\\n\\n懂一点的朋友，也可以直接克隆我的项目，开源的，直接拿去用就行了。\\n\\n地址： [https://github.com/codemyhappy/codemyhappy.github.io](https://github.com/codemyhappy/codemyhappy.github.io)\\n\\n## 总结\\n\\n使用GitHub Pages搭建个人主页有以下优势：\\n- 免费且稳定\\n- 与GitHub无缝集成\\n- 支持自定义域名\\n- 可以使用各种静态网站生成器\\n- 适合开发者展示项目和技能\\n\\n现在你已经了解了如何使用GitHub Pages搭建个人主页的全过程。\\n\\n在下一篇文章中，我将详细介绍如何使用VitePress来创建一个功能丰富的技术博客。\\n\\n感兴趣的朋友可以去我的社交主页，关注我，一起学习。","lastUpdated":1781659724170},{"title":"如何检查macOS系统内安装的electron应用","content":"---\\ntitle: 如何检查 macOS 系统内安装的 Electron 应用\\n---\\n\\n# 如何检查 macOS 系统内安装的 Electron 应用\\n\\n最近清理电脑时，我突然好奇：我的 macOS 里到底装了多少个 Electron 应用？比如 VSCode、Slack、Notion 这些看起来\\"不一样\\"的软件，背后其实都是 Electron 写的。\\n\\n这篇文章就教大家如何找出系统中所有由 Electron 构建的应用程序，顺便也能查出所有\\"内置了浏览器\\"的应用（CEF、Chrome、QtWebEngine 等）。\\n\\n## 什么是 Electron / 内置浏览器的应用？\\n\\n简单来说，**Electron** 是一个用 Web 技术开发桌面应用的框架。它把 Chromium 和 Node.js 打包在一起，外面看是个原生 App，骨子里其实是个浏览器。\\n\\n类似的\\"内置浏览器\\"技术还有：\\n\\n| 技术 | 引擎 | 典型应用 |\\n|------|------|----------|\\n| Electron | Chromium | VSCode、Slack、Notion、Discord |\\n| CEF（Chromium Embedded Framework） | Chromium | 剪映专业版、Spotify、Steam |\\n| Qt WebEngine | Chromium | WPS、OBS 等跨平台应用 |\\n| WebKit | WebKit | 各种带\\"在线预览\\"的小工具 |\\n\\n> **共同点**：都把一个完整的浏览器引擎塞进了自己的 `.app` 包里。\\n\\n## 核心检测方法：`find -name`\\n\\n这些应用有个共同特征——它们的 `.app` 包里都会带一个**特征 framework**。所以检测的核心思路就是：\\n\\n```bash\\nfind /Applications -name \\"<特征 framework 名>\\" -type d 2>/dev/null\\n```\\n\\n> macOS 绝大多数应用都装在 `/Applications` 下，找到 framework 就能反推出应用。\\n\\n下面是常见的 framework 名和对应的引擎：\\n\\n| Framework 名 | 引擎 |\\n|--------------|------|\\n| `Electron Framework.framework` | Electron |\\n| `Chromium Embedded Framework.framework` | CEF |\\n| `Google Chrome Framework.framework` | Chrome |\\n| `Chromium Framework.framework` | Chromium |\\n| `QtWebEngineCore.framework` / `QtWebEngine.framework` | Qt WebEngine |\\n| `WebKit.framework` / `WebKit2.framework` | WebKit |\\n| `MozillaFirefox.framework` / `Gecko.framework` | Firefox |\\n| `nwjs.framework` | NW.js |\\n\\n### 几个常用示例\\n\\n**找出所有 Electron 应用：**\\n\\n```bash\\nfind /Applications -name \\"Electron Framework.framework\\" -type d 2>/dev/null\\n```\\n\\n**找出所有 Chromium 应用：**\\n\\n```bash\\nfind /Applications -name \\"Chromium Framework.framework\\" -type d 2>/dev/null\\n```\\n\\n## 深度排查：用 `otool` 看单个应用\\n\\n`otool` 是 macOS 自带的工具，可以看应用到底链接了哪些 framework。当你不确定某个应用是不是\\"套壳浏览器\\"时，用它最准确。\\n\\n\\n## 使用otool实现的完整可运行的扫描脚本\\n\\n如果你懒得一行一行敲命令，可以直接用下面这个**完整脚本**。它会自动扫描常见位置、检测 18 种浏览器引擎，并输出应用名、版本、占用空间、bundle id 等详细信息。\\n\\n脚本地址：\\n[https://codemyhappy.github.io/static/macshell/detect_browser_apps.sh](https://codemyhappy.github.io/static/macshell/detect_browser_apps.sh)\\n\\n\\n### 使用方法\\n\\n```bash\\nchmod +x detect_browser_apps.sh\\n./detect_browser_apps.sh              # 标准扫描\\n./detect_browser_apps.sh --full       # 深度扫描\\n./detect_browser_apps.sh --deep       # 全用户主目录扫描\\n./detect_browser_apps.sh --json > out.json   # 导出 JSON\\n./detect_browser_apps.sh --csv > out.csv     # 导出 CSV\\n```\\n\\n### 小贴士\\n\\n- 在 **`--deep`** 模式下会扫 `users/` 下的所有用户目录，可能需要 1-3 分钟\\n- 脚本不会修改系统任何文件，**完全只读**，可以放心运行\\n\\n到这里，本文就结束了。希望对你有帮助！\\n","lastUpdated":1781659724170},{"title":"开发了一个APP，我叫它minebook-hot-server","content":"# MineBook Hot Server：个人开发的本地服务智能管理工具\\n\\n**MineBook Hot Server** 是我个人开发的一款用于管理本地开发服务的自动化工具，用于智能监控和管理本地端口，有效减少不必要的系统资源占用。\\n\\n## 背景与需求\\n\\n在我日常的开发工作中，我遇到了一些痛点：\\n\\n- 本地服务端口被占用时，我很难快速定位是哪个进程在运行\\n- 偶尔启动的服务在使用完毕后，我经常会忘记手动关闭\\n- 这些未关闭的服务导致我的电脑内存压力一直很高\\n- 长期下来，我的 MacBook 就会因为内存不足而变得卡顿\\n- 当内存不足时，MacBook 会启用虚拟内存，将硬盘作为交换空间，这样会影响硬盘寿命\\n\\n我相信其他开发者也可能面临类似的困扰。\\n\\n## 个人解决方案\\n\\n基于上述的痛点，作为一个程序员，当然是写个APP来解决咯~\\n\\n于是，我设计并开发了 **MineBook Hot Server** 来解决我自己遇到的这些问题。\\n\\n该工具基于 Tauri 构建，采用 Rust 作为后端语言，前端使用 Web 技术实现。核心技术方案如下：\\n\\n- 后台轮询监听端口流量：系统定期扫描指定端口的流量情况\\n- 活跃度判断：通过检测端口流量变化来判断服务是否处于活跃状态\\n- 智能关闭：如果端口在设定时间内（如30秒）没有流量变化，则判定为不活跃\\n- 进程管理：对不活跃的端口进行 PID 反查，并自动发送终止命令\\n\\n## 界面一览\\n\\n### 主页\\n![alt text](blog-imgs/开发了一个APP，我叫它minebook-hot-server/image-3.png)\\n\\n主页目前提供了基本上所有的功能：\\n- 添加服务：添加新的服务，并保存配置\\n- 修改服务：修改已添加的服务配置\\n- 删除服务：删除已添加的服务\\n- 启动服务：点击端口号即可启动已添加的服务\\n- 停止服务：停止已添加的服务\\n- 复制服务：复制服务启动命令，方便快速创建新的服务端口代理\\n- 端口详情：查看服务详情，包括启动命令、端口号、服务状态、服务创建时间、闲置时间、运行状态、进程ID（PID）\\n\\n### 添加服务弹窗\\n![alt text](blog-imgs/开发了一个APP，我叫它minebook-hot-server/image-4.png)\\n\\n弹窗比较简单，输入必备的服务信息，点击\\"创建服务\\"按钮即可完成服务添加。\\n\\n### 监听端口进程\\n\\n![alt text](blog-imgs/开发了一个APP，我叫它minebook-hot-server/image-6.png)\\n\\n这个页面是一个端口的快速查看页面，能查看当前系统中已经启动的端口服务。\\n\\n也能看到哪些端口已经被minebook-hot-server托管，\\n\\n未托管的端口，可以点击”托管“按钮，快速的完成端口托管。\\n\\n### 后台日志页\\n\\n![alt text](blog-imgs/开发了一个APP，我叫它minebook-hot-server/image-2.png)\\n\\n这是一个后台的日志，如果遇到问题可以快速定位。\\n\\n对于非开发人员估计用不上。\\n\\n## 个人开发总结\\n\\n**MineBook Hot Server** 是我独立设计和实现的项目。从概念设计到功能实现，再到实际部署，整个项目完全由我个人完成。经过一段时间的实际使用验证，该工具在以下方面表现出色：\\n\\n- 有效控制内存占用\\n- 清晰展示当前活跃的本地端口信息\\n- 基于 RUST开发，保证了系统的稳定性\\n\\n如果你也常常为本地服务管理而烦恼，不妨关注我的技术分享，了解这款工具的最新进展。我正在持续优化中，未来版本将增加更多实用功能。欢迎试用并提出宝贵意见，帮助我进一步完善这个工具！","lastUpdated":1781659724170},{"title":"我发现好多人不会安装软件-NodeJS","content":"\\n\\n\\n我发现好多人不会安装软件-NodeJS.md\\n# 我发现好多人不会安装软件-Node.JS\\n\\n最近发现好多新手朋友对如何安装 Node.js 感到困惑。其实安装 Node.js 并不复杂，这篇文章就教大家最简单的方法。\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-1.png)\\n\\n## 什么是 Node.js？\\n\\n简单来说，Node.js 就是让你能在电脑上运行 JavaScript 的环境。无论你是想做前端开发，还是后端服务，或者是最近很火的AI工具，它都是必不可少的前置工具。\\n\\n## 最简单的安装方法\\n\\n访问 Node.js 官方下载页面：[https://nodejs.org/zh-cn/download](https://nodejs.org/zh-cn/download)\\n\\n根据你的操作系统下载对应的安装包：\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image.png)\\n\\n上面的nvm、pnpm等内容，都是可选的，没必要装，徒增复杂度。\\n\\n## Windows 系统安装步骤\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-9.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-10.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-8.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-7.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-3.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-6.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-11.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-12.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-13.png)\\n\\n\\n## Mac 系统安装步骤\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-2.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-4.png)\\n\\n![alt text](blog-imgs/我发现好多人不会安装软件-NodeJS/image-5.png)\\n\\nmacOS的安装非常简单，一直按提示操作，安装完成后，在终端输入 node -v 命令，如果显示版本号，则安装成功。\\n\\n\\n## 常见问题\\n\\n**Q: 安装后命令行显示 \\"node 不是内部或外部命令\\"？**\\nA: 这通常是因为没有正确设置环境变量。请重新安装，在安装时确保勾选了 \\"Add to PATH\\" 选项。\\n\\n**Q: 该选择哪个版本？**\\nA: 新手请选择 LTS 版本，这是稳定版，更适合学习使用。\\n\\n**Q: Mac安装遇到权限问题怎么办？**\\nA: 在安装过程中可能需要输入管理员密码，这是正常现象，输入密码即可继续安装。\\n\\n## 总结\\n\\n安装 Node.js 就这么简单！记住选择 LTS 版本，按照对应系统的安装步骤操作，最后验证一下即可。Node.js 是前端开发的重要工具，掌握了它的安装，你就迈出了开发的第一步！","lastUpdated":1781659724170},{"title":"我的游戏清单","content":"# 我的游戏清单\\n\\n整理一下我喜欢的游戏，标注是否已玩过。\\n\\n## 主要游玩设备\\n\\n- 联想平板 Y700\\n- 苹果手机 14 Plus\\n- MacBook Air M5\\n- Win笔记本 小米14\\n\\n## 游戏列表\\n\\n### 《DNF》[已玩]\\n> 提示：此处需要添加游戏截图\\n\\n玩了很多年，每次登录都有熟悉的感觉，刷图的时候很放松。\\n\\n但太费钱了，没好武器图都过不了，后弃坑。\\n\\n### 《王者荣耀》[已玩]\\n> 提示：此处需要添加游戏截图\\n\\n和朋友开黑必备，有时候一局能玩很久，挺上头的。\\n\\n一分不氪玩了很多年了。\\n\\n### 《阴阳师》[已玩]\\n> 提示：此处需要添加游戏截图\\n\\n画面确实好看，抽卡有点费钱，不过剧情还挺有意思的。\\n\\n后续版本出得太快，英雄/式神出得太快，就不玩了。\\n\\n### 《微信小游戏：别踩白块》[已玩]（我自己做的微信小游戏）\\n> 提示：此处需要添加游戏截图\\n\\n自己动手做的小游戏，虽然简单，但看着自己作品上线还是挺有成就感的。\\n\\n### 《塞尔达传说：旷野之息》 [已玩]\\n> 提示：此处需要添加游戏截图\\n\\n这个游戏让我愿意慢慢玩，到处探索，没有任务压力，很享受。\\n\\n还有很多花活操作：风弹、飞雷神、盾反炸弹、盾反炸弹二段跳、破冰起飞 ...\\n\\n学会一个风弹，就是另一种游戏体验了。\\n\\n### 《塞尔达传说：王国之泪》 [已玩]\\n> 提示：此处需要添加游戏截图\\n\\n个人感觉没旷野之息好玩，画风暗黑、潮湿、破败，某些怪物恶心，没有旷野之息生机勃勃的感觉。\\n\\n但王国之泪可以玩建造diy，综合来看，也算好玩。\\n\\n\\n### 《动物森友会》 [已玩]\\n> 提示：此处需要添加游戏截图\\n\\n个人感觉很轻松，主要是画风可爱，不需要复杂操作。\\n\\n计划给小孩子玩玩。\\n\\n### 《马里奥赛车8》 [已玩]\\n> 提示：此处需要添加游戏截图\\n\\n陪家里孩子玩的，卡通画风，赛道新奇，非常推荐给孩子玩。\\n\\n\\n## 想玩的游戏\\n\\n### 《燕云十六京》\\n![alt text](blog-imgs/我的游戏清单/image-4.png)\\n\\n据说是古风类的开放世界，抽空体验一下\\n\\n### 《pico park2》\\n![alt text](blog-imgs/我的游戏清单/image-2.png)\\n\\n### 《空之轨迹》\\n\\n画风挺喜欢的，还没空玩\\n\\n![alt text](blog-imgs/我的游戏清单/image.png)\\n\\n### 《迷雾北境》\\n\\n依然是画风挺喜欢\\n\\n![alt text](blog-imgs/我的游戏清单/image-3.png)\\n\\n\\n## 不适合我的游戏\\n\\n### 《刺客信条》\\n> 提示：此处需要添加游戏截图\\n\\n太写实了，但又没完全真实，自由度也没那么高。\\n\\n默认设置的视角转动太快，容易晕，不想花时间设置。\\n\\n### 《马里奥奥德赛》\\n> 提示：此处需要添加游戏截图\\n\\n可能是手柄的原因，不适合我的手柄。\\n\\n只能一个人玩，另一个人只能当帽子。\\n\\n对于小孩子来说操作比较复杂，对于我来说，画风又过于低龄。\\n\\n### 《怪物猎人 崛起》\\n\\n![alt text](blog-imgs/我的游戏清单/image-1.png)\\n\\n不喜欢这种页游风。\\n\\n---\\n这份清单会持续更新，记录那些给我带来快乐的游戏时光。","lastUpdated":1781659724170},{"title":"由于喜欢写博文，我写了个vscode插件《markdown-publisher-for-all》，支持markdown多平台一键发布","content":"# 我开发了一个 VSCode 插件《markdown-publisher-for-all》，支持 Markdown 多平台一键发布\\n\\n作为一个热爱写技术博客的人，我经常需要将自己的文章发布到多个平台上，比如 CSDN、简书、知乎、掘金等。但每次手动复制粘贴内容，再上传图片，不仅效率低下，还容易出错。因此，我决定开发一个 VSCode 插件来解决这个问题。\\n\\n## 什么是 markdown-publisher-for-all？\\n\\nmarkdown-publisher-for-all 是一个基于 VSCode 的博文发布客户端，能够一键将 Markdown 文章发布到多个主流博客平台，无需额外的图床服务。\\n\\n> 项目由个人独立开发，专注于提高博主们的发布效率。\\n\\n你可以在 VSCode 插件市场找到它：[markdown-publisher-for-all](https://marketplace.visualstudio.com/items?itemName=brother-xiaohei.markdown-publisher-for-all&ssr=false#overview)\\n\\n## 主要特性\\n\\n### 1. 二维码登录\\n通过扫描二维码快速登录各个平台，免去账号密码的繁琐流程。\\n\\n\\n### 2. 一键多平台发布\\n支持将同一篇文章同时发布到多个平台，包括：\\n- CSDN\\n- 简书\\n- 知乎\\n- 掘金\\n- 其他主流博客平台\\n\\n\\n### 3. 图片自动上传\\n智能识别 Markdown 中的图片链接，并自动上传到对应平台的图床服务，无需手动上传。\\n\\n\\n## 快速开始\\n\\n### 初始配置\\n\\n#### Step 1: 安装 Chrome 浏览器\\n\\n目前插件仅支持 Chrome 浏览器，你需要：\\n\\n1. 安装最新版的 Chrome 浏览器\\n2. 在浏览器地址栏输入 `chrome://version/` 获取浏览器信息\\n3. 记录下 \\"Executable Path\\" 和 \\"User Data Directory\\" 的值\\n\\n#### Step 2: 配置插件设置\\n\\n在工作区的 [.vscode/settings.json]文件中添加以下配置：\\n\\n```json\\n{\\n    \\"MarkdownPublisher.ChromeExecutablePath\\": \\"你的 Chrome 可执行文件路径\\",\\n    \\"MarkdownPublisher.ChromeUserDataDir\\": \\"你的 Chrome 用户数据目录路径\\"\\n}\\n```\\n\\n### 使用方法\\n\\n1. 打开一个编写好的 Markdown 文件\\n2. 在编辑器中右键点击\\n3. 选择需要发布的目标平台\\n4. 插件会自动处理内容并发布到相应平台\\n\\n\\n## 更新日志 (Changelog)\\n\\n### V1.4.0 [Planning]\\n- 加入思否平台的支持\\n\\n### V1.3.6 [Released]\\n- 解决Windows下图片上传的路径问题\\n\\n### V1.3.2 [Released]\\n- 掘金平台图片上传流程修改\\n\\n### V1.3.0 [Released]\\n- 加入知乎平台的支持\\n\\n### V1.2.0 [Released]\\n- 加入掘金平台的支持\\n\\n### V1.1.0 [Released]\\n- 加入简书的支持\\n- 添加配置uploadImageTogether，可控制文章配图是否需要上传\\n\\n### V1.0.0 [Released]\\n- 核心功能完成\\n- 完成对CSDN的一键发文\\n\\n## 问题反馈\\n\\n如果你在使用过程中遇到任何问题，或者有功能建议，欢迎到我的 CSDN 博客留言交流。我将持续改进这个工具，为大家提供更好的体验。\\n\\n## 总结\\n\\n这个插件解决了我自己的痛点，也希望能帮助更多热爱写作的技术人。让我们专注于创作内容本身，而不是繁琐的发布流程。\\n\\n> Now, Enjoy!","lastUpdated":1781659724170}]'),b=["href"],w={__name:"BlogList",setup(m){const i=p.filter(n=>n.title!=="index");return console.log(`\r
所有博文列表：`,p.map(n=>n.title)),(n,v)=>(o(),s("ul",null,[(o(!0),s(d,null,h(l(i),e=>(o(),s("li",{key:e.title},[t("a",{href:`./${e.title}`},a(e.title),9,b),t("span",null,"上次更新： "+a(new Date(e.lastUpdated).toLocaleString()),1)]))),128))]))}},S=c(w,[["__scopeId","data-v-40f64926"]]),M=JSON.parse('{"title":"博客","description":"","frontmatter":{"layout":"home"},"headers":[],"relativePath":"blog/index.md","filePath":"blog/index.md","lastUpdated":1781749489000}'),k={name:"blog/index.md"},y=g({...k,setup(m){return(i,n)=>(o(),s("div",null,[n[0]||(n[0]=t("h1",{id:"博客",tabindex:"-1"},[r("博客 "),t("a",{class:"header-anchor",href:"#博客","aria-label":'Permalink to "博客"'},"​")],-1)),n[1]||(n[1]=t("p",null,"这是我的技术博客页面，记录了我的编程经验、技术思考和项目实践。",-1)),n[2]||(n[2]=t("p",null,"这里的内容会自动更新，请持续关注。",-1)),n[3]||(n[3]=t("h2",{id:"文章列表",tabindex:"-1"},[r("文章列表 "),t("a",{class:"header-anchor",href:"#文章列表","aria-label":'Permalink to "文章列表"'},"​")],-1)),u(S)]))}});export{M as __pageData,y as default};
